Broken or ad-hoc attribute-based authorization in multi-tenant APIs is a common cause of cross-tenant data leaks. You must never trust client-supplied attributes (like tenantId or ownerId) and should centralize access decisions.

**VULNERABLE CODE**:

```typescript
import express, { Request, Response, NextFunction } from 'express';

const app = express();
app.use(express.json());

// Simulated in-memory data store
interface Document {
  id: string;
  tenantId: string;
  ownerId: string;
  content: string;
}

const documents: Document[] = [
  { id: '1', tenantId: 't1', ownerId: 'u1', content: 'Secret for t1-u1' },
  { id: '2', tenantId: 't2', ownerId: 'u2', content: 'Secret for t2-u2' }
];

// Vulnerable: trusts tenantId and ownerId from the request body/query
app.get('/api/docs/:id', (req: Request, res: Response) => {
  const docId = req.params.id;

  // Client is allowed to send arbitrary attributes
  const tenantId = req.query.tenantId as string; // UNSAFE
  const userId = req.query.userId as string;     // UNSAFE

  const doc = documents.find(d => d.id === docId);
  if (!doc) {
    return res.status(404).json({ error: 'Not found' });
  }

  // Broken ABAC: compares against untrusted attributes from client
  if (doc.tenantId !== tenantId || doc.ownerId !== userId) {
    return res.status(403).json({ error: 'Forbidden' });
  }

  // Leaks detailed data
  res.json(doc);
});

app.listen(3000, () => {
  console.log('Vulnerable server running on port 3000');
});
```

**Attack Payload** (exploiting cross-tenant access):
```bash
curl "http://localhost:3000/api/docs/1?tenantId=t1&userId=u1" \
  -H "Authorization: Bearer token-for-user-u2-in-tenant-t2"
```

This payload assumes the attacker is authenticated as `userId=u2` in `tenantId=t2` but simply forges query parameters to access `tenantId=t1` and `userId=u1` data because the server trusts those attributes from the client.

**Why This Is Dangerous**:
- Trusts authorization attributes (`tenantId`, `userId`) directly from the client instead of deriving them from the authenticated session or token.
- Authorization logic is scattered and ad-hoc, making it easy to miss checks and inconsistent policies.
- Returns full document content and detailed error messages, helping attackers probe which IDs exist and which tenants are valid.

**SECURE VERSION**:

```typescript
import express, { Request, Response, NextFunction } from 'express';

const app = express();
app.use(express.json());

interface AuthContext {
  userId: string;
  tenantId: string;
  roles: string[];
}

interface AuthedRequest extends Request {
  auth?: AuthContext;
}

interface Document {
  id: string;
  tenantId: string;
  ownerId: string;
  classification: 'public' | 'internal' | 'confidential';
  content: string;
}

const documents: Document[] = [
  { id: '1', tenantId: 't1', ownerId: 'u1', classification: 'confidential', content: 'Secret for t1-u1' },
  { id: '2', tenantId: 't2', ownerId: 'u2', classification: 'internal', content: 'Secret for t2-u2' }
];

// Fake authentication middleware: in real life, derive from JWT/session
function mockAuth(req: AuthedRequest, _res: Response, next: NextFunction) {
  // DO NOT trust client for tenantId/userId. In real code, decode JWT here.
  // Hard-coded for demo:
  req.auth = {
    userId: 'u2',
    tenantId: 't2',
    roles: ['user']
  };
  next();
}

// Central ABAC check based on server-side attributes
function canAccessDocument(auth: AuthContext, doc: Document): boolean {
  // Tenant isolation: must match tenant
  if (auth.tenantId !== doc.tenantId) {
    return false;
  }

  // Tenant admin can access all docs in tenant
  if (auth.roles.includes('tenant_admin')) {
    return true;
  }

  // Owner can access their own docs
  if (doc.ownerId === auth.userId) {
    return true;
  }

  // Additional attribute-based rules
  if (doc.classification === 'public') {
    return true;
  }

  return false;
}

app.use(mockAuth);

app.get('/api/docs/:id', (req: AuthedRequest, res: Response) => {
  const docId = req.params.id;
  const auth = req.auth;

  if (!auth) {
    return res.status(401).json({ error: 'Unauthorized' });
  }

  // Never use tenantId/userId from query/body for authorization
  const doc = documents.find(d => d.id === docId);
  if (!doc) {
    // Generic 404 to avoid resource enumeration
    return res.status(404).json({ error: 'Not found' });
  }

  if (!canAccessDocument(auth, doc)) {
    // Log minimal info for auditing
    console.warn(`ACCESS_DENIED: user=${auth.userId} tenant=${auth.tenantId} doc=${doc.id}`);
    return res.status(403).json({ error: 'Forbidden' });
  }

  // Return only necessary fields
  res.json({ id: doc.id, content: doc.content });
});

app.listen(3000, () => {
  console.log('Secure-ish ABAC server running on port 3000');
});
```

**Key Security Controls**:
- **Server-derived attributes**: User and tenant attributes are derived from the authenticated context (e.g., JWT, session) instead of trusting client parameters, preventing forged tenantId/userId.
- **Centralized ABAC function**: `canAccessDocument` encapsulates policy based on attributes (tenant, role, owner, classification), making it testable and consistent across endpoints.
- **Secure error handling and logging**: Uses generic error messages to avoid information leaks while logging access denials with minimal identifiers for audit and incident response.

For production, treat authorization as a first-class subsystem: centralize policy evaluation, keep it data-driven, and instrument it for observability. You want consistent decisions across services, clear audit logs, and safe defaults.

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import morgan from 'morgan';

// --- Types ---

interface AuthContext {
  userId: string;
  tenantId: string;
  roles: string[];
  // dynamic attributes
  ip: string;
  time: Date;
  environment: 'dev' | 'prod';
}

interface AuthedRequest extends Request {
  auth?: AuthContext;
}

interface Resource {
  id: string;
  tenantId: string;
  ownerId: string;
  type: 'document' | 'report';
  classification: 'public' | 'internal' | 'confidential';
}

// ABAC policy input
interface PolicyContext {
  action: 'read' | 'write' | 'delete';
  resource: Resource;
  auth: AuthContext;
}

// Result for auditability
interface PolicyResult {
  allowed: boolean;
  reason: string;
}

// --- Policy Engine (centralized) ---

class PolicyEngine {
  evaluate(ctx: PolicyContext): PolicyResult {
    const { action, resource, auth } = ctx;

    // 1. Hard tenant isolation (non-negotiable)
    if (auth.tenantId !== resource.tenantId) {
      return { allowed: false, reason: 'TENANT_MISMATCH' };
    }

    // 2. System / tenant admin roles
    if (auth.roles.includes('system_admin')) {
      return { allowed: true, reason: 'SYSTEM_ADMIN' };
    }
    if (auth.roles.includes('tenant_admin')) {
      return { allowed: true, reason: 'TENANT_ADMIN' };
    }

    // 3. Basic ownership rule
    if (resource.ownerId === auth.userId) {
      return { allowed: true, reason: 'OWNER' };
    }

    // 4. Classification-based rules
    if (action === 'read' && resource.classification === 'public') {
      return { allowed: true, reason: 'PUBLIC_RESOURCE' };
    }

    // 5. Environment & time-based rules (example)
    if (
      auth.environment === 'dev' &&
      action === 'read' &&
      resource.classification !== 'confidential'
    ) {
      return { allowed: true, reason: 'DEV_ENV_RELAXED' };
    }

    const hour = auth.time.getUTCHours();
    if (action === 'write' && (hour < 6 || hour > 22)) {
      // Disallow sensitive writes off-hours
      return { allowed: false, reason: 'OFF_HOURS_WRITE' };
    }

    // 6. Default deny
    return { allowed: false, reason: 'DEFAULT_DENY' };
  }
}

// --- Mock data + auth middleware ---

const documents: Resource[] = [
  { id: '1', tenantId: 't1', ownerId: 'u1', type: 'document', classification: 'confidential' },
  { id: '2', tenantId: 't1', ownerId: 'u2', type: 'report', classification: 'internal' }
];

const policyEngine = new PolicyEngine();

// In real life, derive from JWT/access token
function authMiddleware(req: AuthedRequest, res: Response, next: NextFunction) {
  try {
    const env = (process.env.NODE_ENV === 'production' ? 'prod' : 'dev') as 'dev' | 'prod';

    // Never trust tenantId/userId from request parameters for auth
    // Here we hard-code for demo; in production decode from token
    req.auth = {
      userId: 'u2',
      tenantId: 't1',
      roles: ['user'],
      ip: req.ip,
      time: new Date(),
      environment: env
    };

    next();
  } catch (err) {
    console.error('AUTH_ERROR', { error: String(err) });
    return res.status(401).json({ error: 'Unauthorized' });
  }
}

// --- Express App Setup ---

const app = express();
app.use(express.json());
app.use(morgan('combined'));
app.use(authMiddleware);

// Simple in-memory rate limit per IP (demo only)
const requestCounts: Record<string, { count: number; windowStart: number }> = {};
const WINDOW_MS = 60_000;
const MAX_REQUESTS = 100;

function rateLimit(req: AuthedRequest, res: Response, next: NextFunction) {
  const ip = req.ip || 'unknown';
  const now = Date.now();
  const entry = requestCounts[ip] || { count: 0, windowStart: now };

  if (now - entry.windowStart > WINDOW_MS) {
    entry.count = 0;
    entry.windowStart = now;
  }

  entry.count += 1;
  requestCounts[ip] = entry;

  if (entry.count > MAX_REQUESTS) {
    console.warn('RATE_LIMIT_EXCEEDED', { ip });
    return res.status(429).json({ error: 'Too Many Requests' });
  }

  next();
}

app.use(rateLimit);

// --- Secure route using ABAC engine ---

app.get('/api/docs/:id', (req: AuthedRequest, res: Response) => {
  const auth = req.auth;
  if (!auth) {
    return res.status(401).json({ error: 'Unauthorized' });
  }

  const docId = req.params.id;
  const resource = documents.find(d => d.id === docId);

  // Generic 404 regardless of tenant to avoid enumeration
  if (!resource) {
    return res.status(404).json({ error: 'Not found' });
  }

  const policyResult = policyEngine.evaluate({
    action: 'read',
    resource,
    auth
  });

  // Audit logging of every decision
  console.info('AUTHZ_DECISION', {
    ts: new Date().toISOString(),
    userId: auth.userId,
    tenantId: auth.tenantId,
    resourceId: resource.id,
    action: 'read',
    allowed: policyResult.allowed,
    reason: policyResult.reason,
    ip: auth.ip
  });

  if (!policyResult.allowed) {
    // Fail securely with minimal info
    return res.status(403).json({ error: 'Forbidden' });
  }

  // Successful access: return limited view
  res.json({ id: resource.id, type: resource.type, classification: resource.classification });
});

// Global error handler (defense in depth)
app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
  console.error('UNHANDLED_ERROR', { error: err.message, stack: err.stack });
  res.status(500).json({ error: 'Internal server error' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`ABAC server listening on port ${PORT}`);
});
```

**Defense in Depth Layers**:
1. **Strong tenant isolation and default deny**:
   - In `PolicyEngine.evaluate`:
   ```typescript
   if (auth.tenantId !== resource.tenantId) {
     return { allowed: false, reason: 'TENANT_MISMATCH' };
   }
   // ...
   return { allowed: false, reason: 'DEFAULT_DENY' };
   ```
   Tenant ID is compared only with server-side attributes, with a strict default-deny at the end.

2. **Centralized, audited policy decisions**:
   - Every decision is logged for later review:
   ```typescript
   console.info('AUTHZ_DECISION', {
     ts: new Date().toISOString(),
     userId: auth.userId,
     tenantId: auth.tenantId,
     resourceId: resource.id,
     action: 'read',
     allowed: policyResult.allowed,
     reason: policyResult.reason,
     ip: auth.ip
   });
   ```
   This makes it possible to reconstruct who accessed or attempted to access what and why.

3. **Operational protections: rate limiting and error handling**:
   - Simple IP-based rate limiting to reduce brute-force probing of IDs:
   ```typescript
   if (entry.count > MAX_REQUESTS) {
     console.warn('RATE_LIMIT_EXCEEDED', { ip });
     return res.status(429).json({ error: 'Too Many Requests' });
   }
   ```
   - Global error handler ensures unexpected exceptions do not leak stack traces or internal details.

**Additional Protections**:
- **Environment-specific configuration**: Use `NODE_ENV` to distinguish dev vs prod and feed into the policy (e.g., more relaxed in dev, stricter in prod) while keeping code paths explicit.
- **Security headers and TLS termination**: In a real deployment, run behind a reverse proxy that enforces HTTPS, sets `Strict-Transport-Security`, and adds headers like `X-Content-Type-Options` and `Content-Security-Policy`.
- **Externalized policies and reviews**: For large systems, consider externalizing ABAC policies (e.g., OPA/Styra, Cedar, or similar) so security teams can review and test them independently, and ensure code never bypasses the central policy engine.

GraphQL makes it easy to accidentally expose data because a single endpoint can return many fields, and authorization checks are often forgotten on nested resolvers.

**VULNERABLE CODE**:

```typescript
import { ApolloServer, gql } from 'apollo-server';

interface User {
  id: string;
  role: 'ADMIN' | 'USER';
  email: string;
}

const typeDefs = gql`
  type User {
    id: ID!
    email: String!
    role: String!
  }

  type Query {
    me: User
    user(id: ID!): User
    adminUsers: [User!]!
  }
`;

// In-memory mock data
const users: User[] = [
  { id: '1', role: 'ADMIN', email: 'admin@example.com' },
  { id: '2', role: 'USER', email: 'user@example.com' }
];

const resolvers = {
  Query: {
    // Only me has a weak check, others have none
    me: (_: unknown, __: unknown, ctx: { user?: User }) => {
      return ctx.user || null; // No role or session validation
    },
    user: (_: unknown, args: { id: string }) => {
      // No authorization at all: IDOR via GraphQL
      return users.find(u => u.id === args.id) || null;
    },
    adminUsers: () => {
      // Completely missing admin check
      return users.filter(u => u.role === 'ADMIN');
    }
  }
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    // Trusts a header blindly, attacker can forge it
    const userHeader = req.headers['x-user-id'] as string | undefined;
    const user = users.find(u => u.id === userHeader);
    return { user };
  }
});

server.listen({ port: 4000 }).then(({ url }) => {
  console.log(`🚀 Server ready at ${url}`);
});
```

**Attack Payload** (GraphQL query):
```graphql
# Attacker is logged in as regular USER (id: 2)
# They can still call privileged queries directly

query {
  # Fetch arbitrary user by ID (IDOR)
  user(id: "1") {
    id
    email
    role
  }

  # List admin users, no admin check
  adminUsers {
    id
    email
    role
  }
}
```

**Why This Is Dangerous**:
- No authorization checks on `user` and `adminUsers` allow horizontal privilege escalation and enumeration of privileged accounts.
- Trusting the `x-user-id` header without validation lets attackers impersonate any user by crafting requests.
- Authorization is not enforced per field or resolver, so adding new fields later can silently bypass security reviews.

**SECURE VERSION**:

```typescript
import { ApolloServer, gql, AuthenticationError, ForbiddenError } from 'apollo-server';
import jwt from 'jsonwebtoken';

interface User {
  id: string;
  role: 'ADMIN' | 'USER';
  email: string;
}

interface GraphQLContext {
  user: User | null;
}

const JWT_SECRET = process.env.JWT_SECRET || 'dev-secret-change-me';

const typeDefs = gql`
  enum Role {
    ADMIN
    USER
  }

  type User {
    id: ID!
    email: String!
    role: Role!
  }

  type Query {
    me: User
    user(id: ID!): User
    adminUsers: [User!]!
  }
`;

const users: User[] = [
  { id: '1', role: 'ADMIN', email: 'admin@example.com' },
  { id: '2', role: 'USER', email: 'user@example.com' }
];

function requireAuth(ctx: GraphQLContext): User {
  if (!ctx.user) {
    throw new AuthenticationError('Authentication required');
  }
  return ctx.user;
}

function requireRole(ctx: GraphQLContext, role: 'ADMIN' | 'USER'): User {
  const user = requireAuth(ctx);
  if (user.role !== role) {
    throw new ForbiddenError('Insufficient permissions');
  }
  return user;
}

const resolvers = {
  Query: {
    me: (_: unknown, __: unknown, ctx: GraphQLContext) => {
      // Only return the authenticated user
      return requireAuth(ctx);
    },
    user: (_: unknown, args: { id: string }, ctx: GraphQLContext) => {
      const requester = requireAuth(ctx);

      // Enforce horizontal access control: user can only see themselves
      if (requester.id !== args.id && requester.role !== 'ADMIN') {
        throw new ForbiddenError('Cannot access other users');
      }

      const target = users.find(u => u.id === args.id) || null;
      return target;
    },
    adminUsers: (_: unknown, __: unknown, ctx: GraphQLContext) => {
      requireRole(ctx, 'ADMIN');
      return users.filter(u => u.role === 'ADMIN');
    }
  }
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }): GraphQLContext => {
    const authHeader = req.headers['authorization'];
    if (!authHeader || Array.isArray(authHeader)) {
      return { user: null };
    }

    const token = authHeader.replace('Bearer ', '');
    try {
      const payload = jwt.verify(token, JWT_SECRET) as { id: string; role: User['role']; email: string };
      const user: User = { id: payload.id, role: payload.role, email: payload.email };
      return { user };
    } catch (err) {
      // Log validation failure but return anonymous context
      console.error('JWT verification failed:', err);
      return { user: null };
    }
  },
  formatError: (err) => {
    // Avoid leaking internal details
    console.error('GraphQL error:', err);
    return {
      message: err.message,
      locations: err.locations,
      path: err.path
    };
  }
});

server.listen({ port: 4000 }).then(({ url }) => {
  console.log(`✅ Secure GraphQL server ready at ${url}`);
});
```

**Key Security Controls**:
- Centralized authorization helpers (`requireAuth`, `requireRole`) ensure every resolver explicitly enforces authentication and role checks.
- Strong authentication using signed JWTs from the `Authorization` header instead of trusting spoofable custom headers.
- Proper horizontal access control in the `user` query prevents users from accessing other users' data unless they are admins.

In production, you need consistent, layered authorization that’s enforced close to the data, not just on top-level queries. This is especially critical in GraphQL where new fields and nested resolvers are added frequently.

**PRODUCTION PATTERN**:

```typescript
import { ApolloServer, gql, AuthenticationError, ForbiddenError } from 'apollo-server-express';
import express from 'express';
import jwt from 'jsonwebtoken';
import { GraphQLResolveInfo } from 'graphql';

interface User {
  id: string;
  role: 'ADMIN' | 'USER';
  tenantId: string;
  email: string;
}

interface GraphQLContext {
  user: User | null;
  requestId: string;
  tenantId: string | null;
}

const JWT_SECRET = process.env.JWT_SECRET || 'dev-secret-change-me';
const NODE_ENV = process.env.NODE_ENV || 'development';

const typeDefs = gql`
  enum Role {
    ADMIN
    USER
  }

  type User {
    id: ID!
    email: String!
    role: Role!
    tenantId: ID!
  }

  type Query {
    me: User
    user(id: ID!): User
    tenantUsers(tenantId: ID!): [User!]!
  }
`;

// Example data store
const users: User[] = [
  { id: '1', role: 'ADMIN', tenantId: 't1', email: 'admin@t1.com' },
  { id: '2', role: 'USER', tenantId: 't1', email: 'user1@t1.com' },
  { id: '3', role: 'USER', tenantId: 't2', email: 'user1@t2.com' }
];

// ---- Authorization utilities (defense in depth) ----

function requireAuth(ctx: GraphQLContext): User {
  if (!ctx.user) {
    throw new AuthenticationError('Authentication required');
  }
  return ctx.user;
}

function requireRole(ctx: GraphQLContext, allowed: Array<'ADMIN' | 'USER'>): User {
  const user = requireAuth(ctx);
  if (!allowed.includes(user.role)) {
    throw new ForbiddenError('Insufficient permissions');
  }
  return user;
}

function enforceTenantAccess(ctx: GraphQLContext, resourceTenantId: string): void {
  const user = requireAuth(ctx);
  if (user.tenantId !== resourceTenantId && user.role !== 'ADMIN') {
    throw new ForbiddenError('Cross-tenant access denied');
  }
}

// Field-level authorization wrapper
function withAuth<TArgs = any, TResult = any>(
  resolver: (parent: any, args: TArgs, ctx: GraphQLContext, info: GraphQLResolveInfo) => Promise<TResult> | TResult,
  options?: { roles?: Array<'ADMIN' | 'USER'> }
) {
  return async (parent: any, args: TArgs, ctx: GraphQLContext, info: GraphQLResolveInfo): Promise<TResult> => {
    if (options?.roles) {
      requireRole(ctx, options.roles);
    } else {
      requireAuth(ctx);
    }

    try {
      return await resolver(parent, args, ctx, info);
    } catch (err) {
      console.error(`[${ctx.requestId}] Resolver error in ${info.parentType.name}.${info.fieldName}:`, err);
      throw err;
    }
  };
}

const resolvers = {
  Query: {
    me: withAuth((_: unknown, __: unknown, ctx: GraphQLContext) => {
      return ctx.user;
    }),

    user: withAuth(
      (_: unknown, args: { id: string }, ctx: GraphQLContext) => {
        const target = users.find(u => u.id === args.id) || null;
        if (!target) {
          return null;
        }
        // Horizontal + tenant isolation
        enforceTenantAccess(ctx, target.tenantId);
        const requester = requireAuth(ctx);
        if (requester.id !== target.id && requester.role !== 'ADMIN') {
          throw new ForbiddenError('Cannot access other users in tenant');
        }
        return target;
      },
      { roles: ['ADMIN', 'USER'] }
    ),

    tenantUsers: withAuth(
      (_: unknown, args: { tenantId: string }, ctx: GraphQLContext) => {
        // Tenant-level access control
        enforceTenantAccess(ctx, args.tenantId);
        return users.filter(u => u.tenantId === args.tenantId);
      },
      { roles: ['ADMIN'] } // Only admins can list all users in tenant
    )
  }
};

// ---- Server & context setup ----

function buildContext(req: express.Request): GraphQLContext {
  const authHeader = req.headers['authorization'];
  let user: User | null = null;
  const requestId = (req.headers['x-request-id'] as string) || `${Date.now()}-${Math.random()}`;

  if (authHeader && !Array.isArray(authHeader)) {
    const token = authHeader.replace('Bearer ', '');
    try {
      const payload = jwt.verify(token, JWT_SECRET) as {
        id: string;
        role: User['role'];
        tenantId: string;
        email: string;
      };
      user = {
        id: payload.id,
        role: payload.role,
        tenantId: payload.tenantId,
        email: payload.email
      };
    } catch (err) {
      console.warn(`[${requestId}] Invalid JWT:`, err instanceof Error ? err.message : String(err));
    }
  }

  const tenantId = user?.tenantId || null;

  return { user, requestId, tenantId };
}

const app = express();

// Basic rate limiting example (per reverse proxy or custom middleware in real deployments)
app.use((req, res, next) => {
  // In production, integrate a proper rate limiter (e.g., Redis-backed)
  res.setHeader('X-RateLimit-Policy', 'GraphQL default limits');
  next();
});

// Security headers (for GraphQL playground, etc.)
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  next();
});

const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }): GraphQLContext => buildContext(req as express.Request),
  introspection: NODE_ENV !== 'production',
  plugins: [
    {
      // Simple audit logging plugin
      async requestDidStart(requestContext) {
        const ctx = requestContext.context as GraphQLContext;
        console.info(
          `[${ctx.requestId}] GraphQL request from ${ctx.user?.id || 'anonymous'}:`,
          requestContext.request.operationName
        );
        return {
          willSendResponse(rc) {
            if (rc.errors && rc.errors.length > 0) {
              console.warn(
                `[${ctx.requestId}] GraphQL response with errors:`,
                rc.errors.map(e => e.message)
              );
            }
          }
        };
      }
    }
  ]
});

async function start() {
  await server.start();
  server.applyMiddleware({ app, path: '/graphql' });

  const port = process.env.PORT || 4000;
  app.listen(port, () => {
    console.log(`✅ GraphQL server running on http://localhost:${port}/graphql`);
    console.log(`Environment: ${NODE_ENV}`);
  });
}

start().catch(err => {
  console.error('Failed to start server:', err);
  process.exit(1);
});
```

**Defense in Depth Layers**:
1. **Authentication & Tenant Binding**:
   - JWT-based auth in `buildContext` binds each user to a `tenantId`, which is enforced on every access:
   ```typescript
   const payload = jwt.verify(token, JWT_SECRET) as { id: string; role: User['role']; tenantId: string; email: string };
   user = { id: payload.id, role: payload.role, tenantId: payload.tenantId, email: payload.email };
   ```

2. **Resolver-Level & Field-Level Authorization Wrappers**:
   - `withAuth` wrapper ensures all resolvers opt into authorization explicitly and logs errors with correlation IDs:
   ```typescript
   const resolvers = {
     Query: {
       tenantUsers: withAuth((_, args, ctx) => { /* ... */ }, { roles: ['ADMIN'] })
     }
   };
   ```

3. **Tenant Isolation & Horizontal Access Control**:
   - `enforceTenantAccess` and requester-vs-target checks prevent cross-tenant and cross-user data access:
   ```typescript
   enforceTenantAccess(ctx, target.tenantId);
   if (requester.id !== target.id && requester.role !== 'ADMIN') {
     throw new ForbiddenError('Cannot access other users in tenant');
   }
   ```

**Additional Protections**:
- Environment-specific configuration disables introspection in production and encourages use of proper rate limiting and WAFs.
- Audit logging via Apollo plugins records who did what (user ID, operationName, errors) with `requestId` for correlation.
- Security headers, structured error logging, and centralized auth utilities make it harder for new resolvers to accidentally bypass authorization and easier to detect abuse in monitoring systems.

Exposing internal IDs in URLs is common, but it becomes dangerous when the backend does not enforce proper authorization checks. This is a classic Insecure Direct Object Reference (IDOR) issue.

**VULNERABLE CODE**:

```typescript
import express, { Request, Response } from 'express';
import { Pool } from 'pg';

const app = express();
const pool = new Pool({ connectionString: process.env.DATABASE_URL });

// Fake auth middleware that only sets userId from a decoded token
app.use((req: Request, _res: Response, next) => {
  // In reality you'd verify JWT, etc.
  (req as any).user = { id: 42, role: 'customer' };
  next();
});

// ❌ IDOR: any logged-in user can access any order if they guess the ID
app.get('/api/orders/:orderId', async (req: Request, res: Response) => {
  const orderId = req.params.orderId; // e.g., 1001, 1002, ...

  try {
    const result = await pool.query(
      'SELECT id, user_id, total_amount, status FROM orders WHERE id = $1',
      [orderId]
    );

    if (result.rowCount === 0) {
      return res.status(404).json({ error: 'Order not found' });
    }

    // ❌ No check that this order belongs to the current user
    return res.json(result.rows[0]);
  } catch (err) {
    console.error('DB error', err);
    return res.status(500).json({ error: 'Internal server error' });
  }
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});
```

**Attack Payload** (if applicable):
```bash
# Attacker is logged in as user A but wants to see user B's orders
curl -H "Authorization: Bearer <token-of-user-A>" \
  https://api.example.com/api/orders/1009

# They simply iterate over IDs
for id in $(seq 1000 1050); do
  curl -s -H "Authorization: Bearer <token-of-user-A>" \
    "https://api.example.com/api/orders/$id" | jq '.user_id, .total_amount';
done
```

**Why This Is Dangerous**:
- Any authenticated user can enumerate sequential `orderId` values and access other users' orders.
- Leaks sensitive PII and financial data, violating privacy regulations and compliance requirements.
- Attack is low‑skill and hard to detect if logs don't explicitly capture authorization failures.

**SECURE VERSION**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import { Pool } from 'pg';

const app = express();
const pool = new Pool({ connectionString: process.env.DATABASE_URL });

interface AuthenticatedRequest extends Request {
  user?: { id: number; role: 'customer' | 'admin' };
}

// Simulated auth middleware
function authMiddleware(req: AuthenticatedRequest, _res: Response, next: NextFunction) {
  // Normally: verify JWT/session, load user from DB, etc.
  req.user = { id: 42, role: 'customer' };
  next();
}

app.use(authMiddleware);

// ✅ Secure: enforce ownership check and role-based access
app.get('/api/orders/:orderId', async (req: AuthenticatedRequest, res: Response) => {
  if (!req.user) {
    return res.status(401).json({ error: 'Unauthenticated' });
  }

  const rawOrderId = req.params.orderId;
  const orderId = Number(rawOrderId);

  // Basic input validation
  if (!Number.isInteger(orderId) || orderId <= 0) {
    return res.status(400).json({ error: 'Invalid order ID' });
  }

  try {
    // PRIMARY DEFENSE: Scope query to user ID unless admin
    let result;

    if (req.user.role === 'admin') {
      // Admins can access any order
      result = await pool.query(
        'SELECT id, user_id, total_amount, status FROM orders WHERE id = $1',
        [orderId]
      );
    } else {
      // Regular users can only access their own orders
      result = await pool.query(
        'SELECT id, user_id, total_amount, status FROM orders WHERE id = $1 AND user_id = $2',
        [orderId, req.user.id]
      );
    }

    if (result.rowCount === 0) {
      // Avoid leaking whether the order exists for someone else
      return res.status(404).json({ error: 'Order not found' });
    }

    // Optionally, trim sensitive fields before returning
    const order = result.rows[0];
    return res.json({
      id: order.id,
      totalAmount: order.total_amount,
      status: order.status
    });
  } catch (err) {
    console.error('DB error while fetching order', err);
    return res.status(500).json({ error: 'Internal server error' });
  }
});

app.listen(3000, () => {
  console.log('Secure server running on port 3000');
});
```

**Key Security Controls**:
- Ownership checks in the data access layer: the SQL query is scoped by both `orderId` and `user_id`, preventing users from seeing others' data.
- Role-based access control (RBAC): admins have broader rights, but regular users are restricted to their own resources.
- Input validation and safe error handling: invalid IDs are rejected with 400, and missing orders return a generic 404 without revealing whether they belong to another user.

In production, IDOR prevention needs consistent authorization checks across all entry points and services, not just a single route. You should centralize authorization logic, log decisions, and design APIs around access control, not just internal IDs.

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import { Pool } from 'pg';
import morgan from 'morgan';

const app = express();
const pool = new Pool({ connectionString: process.env.DATABASE_URL });

interface User {
  id: number;
  role: 'customer' | 'support' | 'admin';
}

interface AuthedRequest extends Request {
  user?: User;
}

// Environment-specific configuration
const ENV = process.env.NODE_ENV || 'development';
const PORT = Number(process.env.PORT || 3000);

// Basic request logging (no sensitive data)
app.use(morgan(ENV === 'production' ? 'combined' : 'dev'));

// Security headers (minimal example)
app.use((req: Request, res: Response, next: NextFunction) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '0');
  next();
});

// Simulated authentication middleware
function authMiddleware(req: AuthedRequest, res: Response, next: NextFunction) {
  // In real code, decode JWT / session and fetch user
  const fakeUserId = req.header('X-Debug-UserId');
  const id = fakeUserId ? Number(fakeUserId) : 42;
  req.user = { id, role: id === 1 ? 'admin' : 'customer' };
  next();
}

app.use(authMiddleware);

// Central authorization helper
function authorizeOrderAccess(
  req: AuthedRequest,
  targetUserId?: number
): { allowed: boolean; reason?: string } {
  const user = req.user;
  if (!user) {
    return { allowed: false, reason: 'unauthenticated' };
  }

  if (user.role === 'admin') {
    return { allowed: true };
  }

  if (typeof targetUserId === 'number') {
    if (user.id === targetUserId) {
      return { allowed: true };
    }
    return { allowed: false, reason: 'forbidden_other_user' };
  }

  return { allowed: false, reason: 'missing_target_user' };
}

// Rate limiting (very naive example; use a library like express-rate-limit in real apps)
const rateMap = new Map<string, { count: number; ts: number }>();
function rateLimit(maxPerMinute: number) {
  return (req: Request, res: Response, next: NextFunction) => {
    const key = req.ip;
    const now = Date.now();
    const record = rateMap.get(key) || { count: 0, ts: now };
    if (now - record.ts > 60_000) {
      record.count = 0;
      record.ts = now;
    }
    record.count++;
    rateMap.set(key, record);

    if (record.count > maxPerMinute) {
      return res.status(429).json({ error: 'Too many requests' });
    }
    next();
  };
}

// GET /api/orders/:orderId - single order with IDOR-safe access
app.get('/api/orders/:orderId', rateLimit(60), async (req: AuthedRequest, res: Response) => {
  const user = req.user;
  if (!user) {
    return res.status(401).json({ error: 'Unauthenticated' });
  }

  const orderId = Number(req.params.orderId);
  if (!Number.isInteger(orderId) || orderId <= 0) {
    return res.status(400).json({ error: 'Invalid order ID' });
  }

  try {
    // Always load with user_id to enforce ownership at DB layer
    const result = await pool.query(
      'SELECT id, user_id, total_amount, status FROM orders WHERE id = $1',
      [orderId]
    );

    if (result.rowCount === 0) {
      return res.status(404).json({ error: 'Order not found' });
    }

    const order = result.rows[0];
    const decision = authorizeOrderAccess(req, order.user_id);

    if (!decision.allowed) {
      console.warn('Authorization denied for order access', {
        userId: user.id,
        role: user.role,
        orderId,
        reason: decision.reason
      });
      return res.status(403).json({ error: 'Forbidden' });
    }

    return res.json({
      id: order.id,
      totalAmount: order.total_amount,
      status: order.status
    });
  } catch (err) {
    console.error('DB error while fetching order', err);
    return res.status(503).json({ error: 'Service unavailable' }); // graceful degradation
  }
});

// GET /api/users/:userId/orders?page=&pageSize= - list with pagination and RBAC
app.get('/api/users/:userId/orders', rateLimit(60), async (req: AuthedRequest, res: Response) => {
  const targetUserId = Number(req.params.userId);
  const page = Number(req.query.page || 1);
  const pageSize = Math.min(Number(req.query.pageSize || 20), 100);

  if (!Number.isInteger(targetUserId) || targetUserId <= 0) {
    return res.status(400).json({ error: 'Invalid user ID' });
  }
  if (!Number.isInteger(page) || page <= 0) {
    return res.status(400).json({ error: 'Invalid page' });
  }

  const decision = authorizeOrderAccess(req, targetUserId);
  if (!decision.allowed) {
    const user = req.user!;
    console.warn('Authorization denied for order list', {
      userId: user.id,
      role: user.role,
      targetUserId,
      reason: decision.reason
    });
    return res.status(403).json({ error: 'Forbidden' });
  }

  const offset = (page - 1) * pageSize;

  try {
    const result = await pool.query(
      'SELECT id, total_amount, status FROM orders WHERE user_id = $1 ORDER BY id DESC LIMIT $2 OFFSET $3',
      [targetUserId, pageSize, offset]
    );

    return res.json({
      page,
      pageSize,
      orders: result.rows.map((o: any) => ({
        id: o.id,
        totalAmount: o.total_amount,
        status: o.status
      }))
    });
  } catch (err) {
    console.error('DB error while listing orders', err);
    return res.status(503).json({ error: 'Service unavailable' });
  }
});

// Central error handler as last middleware
app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
  console.error('Unhandled error', err);
  res.status(500).json({ error: 'Internal server error' });
});

app.listen(PORT, () => {
  console.log(`API server listening on port ${PORT} in ${ENV} mode`);
});
```

**Defense in Depth Layers**:
1. Centralized authorization logic
   - The `authorizeOrderAccess` function enforces who can access which user's data, and is reused across endpoints:
   ```typescript
   const decision = authorizeOrderAccess(req, targetUserId);
   if (!decision.allowed) {
     return res.status(403).json({ error: 'Forbidden' });
   }
   ```
2. Data-layer scoping and validation
   - Queries are always scoped by `user_id` where appropriate, and inputs are validated before hitting the DB:
   ```typescript
   const result = await pool.query(
     'SELECT id, total_amount, status FROM orders WHERE user_id = $1 ORDER BY id DESC LIMIT $2 OFFSET $3',
     [targetUserId, pageSize, offset]
   );
   ```
3. Monitoring, rate limiting, and secure defaults
   - Rate limiting, logging of denied access, and environment-aware logging form additional layers:
   ```typescript
   app.use(morgan(ENV === 'production' ? 'combined' : 'dev'));
   console.warn('Authorization denied for order list', { userId: user.id, targetUserId });
   app.get('/api/orders/:orderId', rateLimit(60), handler);
   ```

**Additional Protections**:
- Use non-guessable identifiers (e.g., UUIDs) instead of sequential integers to make enumeration harder, while still enforcing server-side authorization.
- Apply the same authorization checks in all services that touch the same data (API gateway, internal services, background jobs) to avoid IDORs via secondary channels.
- Implement audit logging for sensitive operations (viewing another user's orders, admin access) and feed these logs into alerting systems to detect abuse patterns.

When handling file uploads, it's not enough to authenticate the user; you must also enforce **authorization** on the target resource (e.g., which user or project owns the file). A common mistake is trusting client-supplied IDs (like `userId` or `projectId`) without verifying that the authenticated user is allowed to upload for that ID.

**VULNERABLE CODE**:

```typescript
import express, { Request, Response } from 'express';
import multer from 'multer';
import path from 'path';
import fs from 'fs';

const app = express();
const upload = multer({ dest: 'uploads/' });

// Fake "authentication" middleware that only sets req.userId
app.use((req: Request, _res: Response, next) => {
  // In reality this would parse a JWT or session
  (req as any).userId = req.headers['x-user-id'];
  next();
});

// VULNERABLE: no authorization check on target userId
app.post('/api/users/:userId/avatar', upload.single('avatar'), (req: Request, res: Response) => {
  const requesterId = (req as any).userId; // Attacker-controlled header
  const targetUserId = req.params.userId;  // From URL path

  if (!requesterId) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  // Assumes if authenticated, user can upload for ANY userId
  const file = (req as any).file;
  if (!file) {
    return res.status(400).json({ error: 'No file uploaded' });
  }

  const destDir = path.join(__dirname, 'user-avatars', targetUserId);
  if (!fs.existsSync(destDir)) {
    fs.mkdirSync(destDir, { recursive: true });
  }
  const destPath = path.join(destDir, file.originalname);
  fs.renameSync(file.path, destPath);

  return res.json({
    message: 'Avatar uploaded',
    path: `/user-avatars/${targetUserId}/${file.originalname}`
  });
});

app.listen(3000, () => {
  console.log('Server listening on port 3000');
});
```

**Attack Payload** (HTTP request exploiting broken authorization):

```bash
curl -X POST "https://api.example.com/api/users/victimUserId/avatar" \
  -H "x-user-id: attackerUserId" \
  -F "avatar=@/tmp/webshell.php"
```

This lets the attacker upload or overwrite the avatar for `victimUserId` just by changing the URL parameter.

**Why This Is Dangerous**:
- Any authenticated user can upload files **on behalf of any other user** by changing `:userId` in the path.
- If these files are later served publicly, an attacker can overwrite or plant malicious files (e.g., HTML/JS, scripts on misconfigured servers).
- Lack of audit controls makes it hard to detect abuse; logs only show a generic upload event.

**SECURE VERSION**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import multer from 'multer';
import path from 'path';
import fs from 'fs';

const app = express();
const upload = multer({ dest: 'uploads/' });

interface AuthenticatedRequest extends Request {
  user?: { id: string; role: 'user' | 'admin' };
}

// Proper authentication middleware (simplified)
function authMiddleware(req: AuthenticatedRequest, res: Response, next: NextFunction) {
  const userIdHeader = req.headers['x-user-id'];
  const roleHeader = req.headers['x-user-role'];

  if (!userIdHeader || typeof userIdHeader !== 'string') {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  req.user = {
    id: userIdHeader,
    role: roleHeader === 'admin' ? 'admin' : 'user'
  };

  next();
}

// Authorization helper: can the caller modify this user's avatar?
function canModifyUserAvatar(requester: { id: string; role: string }, targetUserId: string): boolean {
  if (requester.role === 'admin') {
    return true; // Admins can update any avatar (business decision)
  }
  // Regular users can only modify their own avatar
  return requester.id === targetUserId;
}

app.use(authMiddleware);

app.post('/api/users/:userId/avatar', upload.single('avatar'), (req: AuthenticatedRequest, res: Response) => {
  const requester = req.user;
  const targetUserId = req.params.userId;

  if (!requester) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  // PRIMARY DEFENSE: enforce authorization on the target resource
  if (!canModifyUserAvatar(requester, targetUserId)) {
    console.warn(`Unauthorized avatar upload attempt by user ${requester.id} for user ${targetUserId}`);
    return res.status(403).json({ error: 'Not authorized to modify this user avatar' });
  }

  const file = (req as any).file as Express.Multer.File | undefined;
  if (!file) {
    return res.status(400).json({ error: 'No file uploaded' });
  }

  // DEFENSE IN DEPTH: basic file validation (e.g., images only)
  const allowedMimeTypes = ['image/png', 'image/jpeg', 'image/gif'];
  if (!allowedMimeTypes.includes(file.mimetype)) {
    fs.unlink(file.path, () => {}); // Remove temp file
    console.warn(`User ${requester.id} tried to upload disallowed file type: ${file.mimetype}`);
    return res.status(400).json({ error: 'Invalid file type' });
  }

  try {
    const destDir = path.join(__dirname, 'user-avatars', targetUserId);
    if (!fs.existsSync(destDir)) {
      fs.mkdirSync(destDir, { recursive: true });
    }

    // Normalize and restrict filename
    const safeFileName = path.basename(file.originalname).replace(/[^a-zA-Z0-9_.-]/g, '_');
    const destPath = path.join(destDir, safeFileName);

    fs.renameSync(file.path, destPath);

    console.info(`User ${requester.id} uploaded avatar for ${targetUserId}: ${safeFileName}`);

    return res.json({
      message: 'Avatar uploaded',
      path: `/user-avatars/${targetUserId}/${safeFileName}`
    });
  } catch (err) {
    console.error('Avatar upload error:', err);
    // Fail securely without leaking internals
    return res.status(500).json({ error: 'Internal server error' });
  }
});

app.listen(3000, () => {
  console.log('Secure avatar upload server listening on port 3000');
});
```

**Key Security Controls**:
- **Explicit authorization check on target resource**: `canModifyUserAvatar` ensures a user can only upload for themselves (or an admin for others), preventing ID-tampering attacks.
- **File validation and sanitization**: Restricting MIME types and normalizing filenames reduces the risk of script uploads, path traversal, or overwriting sensitive files.
- **Secure logging and error handling**: Logging unauthorized attempts and upload activity enables monitoring, while generic error messages avoid leaking sensitive details.

In production, you typically have a richer permission model: users belong to organizations/teams, projects have roles (owner, editor, viewer), and you may have shared folders or collections. You should centralize authorization decisions, add rate limiting, structured logging, and environment-specific behavior.

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import multer from 'multer';
import path from 'path';
import fs from 'fs';
import rateLimit from 'express-rate-limit';

// Simulated configuration
const ENV = process.env.NODE_ENV || 'development';
const MAX_FILE_SIZE_BYTES = 5 * 1024 * 1024; // 5MB

// Multer with file size limit
const upload = multer({
  dest: 'uploads/',
  limits: { fileSize: MAX_FILE_SIZE_BYTES }
});

// Basic in-memory role model for demo
// In production, replace with a database/ACL service
interface UserContext {
  id: string;
  role: 'global_admin' | 'user';
}

interface ProjectRole {
  userId: string;
  projectId: string;
  role: 'owner' | 'editor' | 'viewer';
}

const projectRoles: ProjectRole[] = [
  { userId: 'u1', projectId: 'p1', role: 'owner' },
  { userId: 'u2', projectId: 'p1', role: 'editor' },
  { userId: 'u3', projectId: 'p1', role: 'viewer' }
];

interface AuthenticatedRequest extends Request {
  user?: UserContext;
}

// Centralized logger (simplified)
function logSecurity(event: string, details: Record<string, unknown>) {
  const payload = {
    ts: new Date().toISOString(),
    event,
    env: ENV,
    ...details
  };
  console.log(JSON.stringify(payload));
}

// Authentication middleware
function authMiddleware(req: AuthenticatedRequest, res: Response, next: NextFunction) {
  const userIdHeader = req.headers['x-user-id'];
  const roleHeader = req.headers['x-user-role'];

  if (!userIdHeader || typeof userIdHeader !== 'string') {
    logSecurity('auth.failed', { ip: req.ip, reason: 'missing_user_id_header' });
    return res.status(401).json({ error: 'Not authenticated' });
  }

  req.user = {
    id: userIdHeader,
    role: roleHeader === 'global_admin' ? 'global_admin' : 'user'
  };

  next();
}

// Centralized project permission check
function getUserProjectRole(userId: string, projectId: string): 'owner' | 'editor' | 'viewer' | null {
  const pr = projectRoles.find(r => r.userId === userId && r.projectId === projectId);
  return pr ? pr.role : null;
}

// Can this user upload to this project folder?
function canUploadToProjectFolder(user: UserContext, projectId: string, folderId: string): boolean {
  if (user.role === 'global_admin') {
    return true;
  }

  const projectRole = getUserProjectRole(user.id, projectId);
  if (!projectRole) {
    return false; // No access to project at all
  }

  // Owners and editors can upload; viewers cannot
  if (projectRole === 'owner' || projectRole === 'editor') {
    return true;
  }

  // Additional policies (e.g., allow viewer uploads to specific folders) could go here
  return false;
}

// Rate limiting: stricter on upload endpoint
const uploadRateLimiter = rateLimit({
  windowMs: 5 * 60 * 1000, // 5 minutes
  max: 20, // 20 upload requests per IP per window
  standardHeaders: true,
  legacyHeaders: false
});

const app = express();

// Security headers (partial)
app.use((req: Request, res: Response, next: NextFunction) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '0');
  next();
});

app.use(authMiddleware);

app.post(
  '/api/projects/:projectId/folders/:folderId/files',
  uploadRateLimiter,
  upload.single('file'),
  async (req: AuthenticatedRequest, res: Response) => {
    const user = req.user;
    const { projectId, folderId } = req.params;

    if (!user) {
      return res.status(401).json({ error: 'Not authenticated' });
    }

    const file = (req as any).file as Express.Multer.File | undefined;
    if (!file) {
      return res.status(400).json({ error: 'No file uploaded' });
    }

    // Primary authorization check
    if (!canUploadToProjectFolder(user, projectId, folderId)) {
      logSecurity('upload.denied', {
        userId: user.id,
        projectId,
        folderId,
        reason: 'insufficient_role',
        ip: req.ip
      });
      // Remove temp file to avoid accumulation
      fs.unlink(file.path, () => {});
      return res.status(403).json({ error: 'Not authorized to upload to this folder' });
    }

    // Defense in depth: file type and name validation
    const allowedMimeTypes = ['application/pdf', 'image/png', 'image/jpeg', 'text/plain'];
    if (!allowedMimeTypes.includes(file.mimetype)) {
      fs.unlink(file.path, () => {});
      logSecurity('upload.blocked_type', {
        userId: user.id,
        projectId,
        folderId,
        mimetype: file.mimetype,
        filename: file.originalname
      });
      return res.status(400).json({ error: 'Invalid file type' });
    }

    const safeFileName = path
      .basename(file.originalname)
      .replace(/[^a-zA-Z0-9_.-]/g, '_')
      .slice(0, 100); // limit length

    const destDir = path.join(__dirname, 'project-files', projectId, folderId);

    try {
      await fs.promises.mkdir(destDir, { recursive: true });
      const destPath = path.join(destDir, safeFileName);
      await fs.promises.rename(file.path, destPath);

      logSecurity('upload.success', {
        userId: user.id,
        projectId,
        folderId,
        filename: safeFileName,
        size: file.size
      });

      return res.status(201).json({
        message: 'File uploaded',
        file: {
          name: safeFileName,
          projectId,
          folderId
        }
      });
    } catch (err) {
      // Clean up temp file on error
      fs.unlink(file.path, () => {});
      logSecurity('upload.error', {
        userId: user.id,
        projectId,
        folderId,
        error: (err as Error).message
      });
      return res.status(500).json({ error: 'Internal server error' });
    }
  }
);

// Graceful degradation and environment-specific behavior
app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
  logSecurity('unhandled.error', { message: err.message, stack: ENV === 'production' ? undefined : err.stack });
  if (ENV === 'production') {
    return res.status(500).json({ error: 'Internal server error' });
  }
  return res.status(500).json({ error: err.message, stack: err.stack });
});

app.listen(3000, () => {
  console.log(`Production-style file upload service running in ${ENV} mode on port 3000`);
});
```

**Defense in Depth Layers**:
1. **Centralized authorization logic**: 
   - `canUploadToProjectFolder` and `getUserProjectRole` encapsulate role checks so that all upload endpoints use the same, audited policy.
   - Example:
   ```typescript
   if (!canUploadToProjectFolder(user, projectId, folderId)) {
     return res.status(403).json({ error: 'Not authorized to upload to this folder' });
   }
   ```
2. **Rate limiting and input validation**:
   - `uploadRateLimiter` caps upload attempts per IP, mitigating brute-force or abuse.
   - File size and MIME type limits reduce DoS and malicious content risk.
   - Example:
   ```typescript
   const upload = multer({ limits: { fileSize: MAX_FILE_SIZE_BYTES } });
   const allowedMimeTypes = ['application/pdf', 'image/png'];
   ```
3. **Secure logging, error handling, and headers**:
   - `logSecurity` produces structured JSON logs for SIEM/monitoring.
   - Error handler hides stack traces in production while logging details.
   - Security headers harden the service when files are later served via the same app or reverse proxy.
   - Example:
   ```typescript
   logSecurity('upload.denied', { userId: user.id, projectId, folderId });
   res.setHeader('X-Content-Type-Options', 'nosniff');
   ```

**Additional Protections**:
- Integrate with a dedicated **authorization service or policy engine** (e.g., OPA, Cedar, or internal RBAC service) instead of hardcoding roles in code.
- Run uploaded files through **malware scanning** and store them on isolated object storage (e.g., S3) with strict bucket policies rather than local disk.
- Implement **audit trails and anomaly detection**: track unusual upload patterns (sudden spikes, cross-project uploads) and alert security teams or temporarily suspend suspicious accounts.

A common mistake is to rely on client-supplied roles or to only protect some endpoints. That leads to broken access control where normal users can call admin APIs.

**VULNERABLE CODE**:

```typescript
import express, { Request, Response, NextFunction } from 'express';

const app = express();
app.use(express.json());

// ❌ Role is trusted from the client body/header (attacker-controlled)
interface AuthenticatedRequest extends Request {
  user?: { id: string; role: string };
}

// Fake auth that just reads role from header
function fakeAuth(req: AuthenticatedRequest, _res: Response, next: NextFunction) {
  const userId = req.header('X-User-Id') || 'anonymous';
  const roleFromClient = req.header('X-User-Role') || 'user'; // ❌ attacker-controlled

  req.user = {
    id: userId,
    role: roleFromClient
  };

  next();
}

app.use(fakeAuth);

// ❌ Insecure RBAC: trusts req.user.role without server-side verification
app.post('/admin/users', (req: AuthenticatedRequest, res: Response) => {
  if (req.user?.role !== 'admin') {
    return res.status(403).json({ message: 'Admins only' });
  }

  // Create user logic (omitted)
  const { email } = req.body;
  // ... insert into DB without any further checks
  return res.json({ message: `User ${email} created by ${req.user.id}` });
});

// Public profile endpoint (no auth check at all)
app.get('/admin/users', (_req: Request, res: Response) => {
  // ❌ Anyone can list all users (no authorization)
  res.json([{ id: '1', email: 'admin@example.com' }]);
});

app.listen(3000, () => {
  console.log('Vulnerable server listening on port 3000');
});
```

**Attack Payload** (abusing client-controlled role header):
```bash
curl -X POST http://localhost:3000/admin/users \
  -H 'Content-Type: application/json' \
  -H 'X-User-Id: attacker' \
  -H 'X-User-Role: admin' \
  -d '{"email": "victim@example.com"}'
```

This request forges the `X-User-Role: admin` header so an unprivileged attacker can create users via the admin endpoint.

**Why This Is Dangerous**:
- Trusts authorization data (role) coming from the client instead of the server-side identity store.
- Fails to enforce any authorization on a sensitive listing endpoint (`GET /admin/users`).
- No defense-in-depth: no audit logging, no privilege minimization, and no separation between authentication and authorization.

**SECURE VERSION**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';

const app = express();
app.use(express.json());

// In real apps, keep this secret in an environment variable
const JWT_PUBLIC_KEY = '-----BEGIN PUBLIC KEY-----\n...public key...\n-----END PUBLIC KEY-----';

// Strongly-typed roles
type Role = 'user' | 'admin' | 'support';

interface AuthenticatedUser {
  id: string;
  role: Role;
}

interface AuthenticatedRequest extends Request {
  user?: AuthenticatedUser;
}

// ✅ Authentication middleware: validate and decode JWT issued by your auth server
function jwtAuth(req: AuthenticatedRequest, res: Response, next: NextFunction) {
  const authHeader = req.header('Authorization');
  if (!authHeader?.startsWith('Bearer ')) {
    return res.status(401).json({ message: 'Missing or invalid Authorization header' });
  }

  const token = authHeader.substring('Bearer '.length);

  try {
    // In real apps, verify signature using your auth server's public key
    const decoded = jwt.verify(token, JWT_PUBLIC_KEY) as { sub: string; role: Role };

    // ✅ Role and user id come from trusted token, not client-controlled headers
    req.user = {
      id: decoded.sub,
      role: decoded.role
    };

    return next();
  } catch (err) {
    console.error('JWT verification failed', err);
    return res.status(401).json({ message: 'Invalid token' });
  }
}

// ✅ Authorization middleware for RBAC
function requireRole(allowedRoles: Role[]) {
  return (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
    if (!req.user) {
      return res.status(401).json({ message: 'Not authenticated' });
    }

    if (!allowedRoles.includes(req.user.role)) {
      // Log denied access for auditing
      console.warn('Access denied', {
        userId: req.user.id,
        role: req.user.role,
        path: req.path,
        method: req.method
      });
      return res.status(403).json({ message: 'Forbidden' });
    }

    return next();
  };
}

app.use(jwtAuth);

// ✅ Admin-only endpoint protected by RBAC middleware
app.post('/admin/users', requireRole(['admin']), (req: AuthenticatedRequest, res: Response) => {
  const { email } = req.body;
  if (typeof email !== 'string' || !email.includes('@')) {
    return res.status(400).json({ message: 'Invalid email' });
  }

  try {
    // Create user in DB (pseudo code)
    const newUser = { id: '123', email };

    console.info('User created', {
      createdBy: req.user?.id,
      newUserId: newUser.id
    });

    return res.status(201).json({ id: newUser.id, email: newUser.email });
  } catch (err) {
    console.error('Error creating user', err);
    // ✅ Fail securely without leaking internal details
    return res.status(500).json({ message: 'Internal server error' });
  }
});

// ✅ Also protect listing of users
app.get('/admin/users', requireRole(['admin', 'support']), (req: AuthenticatedRequest, res: Response) => {
  try {
    // Fetch users (pseudo code)
    const users = [
      { id: '1', email: 'admin@example.com' },
      { id: '2', email: 'user@example.com' }
    ];

    console.info('User list accessed', {
      requestedBy: req.user?.id,
      count: users.length
    });

    return res.json(users);
  } catch (err) {
    console.error('Error fetching users', err);
    return res.status(500).json({ message: 'Internal server error' });
  }
});

app.listen(3001, () => {
  console.log('Secure RBAC server listening on port 3001');
});
```

**Key Security Controls**:
- **Server-side authorization source**: Roles and user IDs are taken from a signed JWT issued by a trusted auth server, not from headers or request bodies controlled by the client.
- **Centralized RBAC middleware**: The `requireRole` middleware centralizes authorization logic and is applied consistently on every sensitive route, reducing the chance of missing checks.
- **Secure error handling and logging**: Access denials and server errors are logged with minimal but useful context, while responses avoid leaking internal implementation details.

In production, you typically combine global roles (like system admin) with resource-scoped permissions (like project admin or project viewer). You also need layered controls: centralized authorization, consistent policy evaluation, proper logging, and environment-specific hardening.

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';
import rateLimit from 'express-rate-limit';

// ---- Types & Models ----

type GlobalRole = 'system_admin' | 'support' | 'user';

type ProjectRole = 'project_owner' | 'project_admin' | 'project_editor' | 'project_viewer';

interface AuthenticatedUser {
  id: string;
  globalRole: GlobalRole;
}

interface AuthenticatedRequest extends Request {
  user?: AuthenticatedUser;
}

interface ProjectMembership {
  userId: string;
  projectId: string;
  role: ProjectRole;
}

// Simulated DB access layer
class ProjectRepository {
  async getMembership(userId: string, projectId: string): Promise<ProjectMembership | null> {
    // In real code, query your DB using parameterized queries
    if (userId === '1' && projectId === 'p1') {
      return { userId, projectId, role: 'project_admin' };
    }
    return null;
  }
}

const projectRepo = new ProjectRepository();

// ---- Environment & App Setup ----

const app = express();
app.use(express.json());

const ENV = process.env.NODE_ENV || 'development';
const JWT_PUBLIC_KEY = process.env.JWT_PUBLIC_KEY || 'dev-public-key';

// Basic rate limiting: more strict on admin endpoints
const adminLimiter = rateLimit({
  windowMs: 1 * 60 * 1000,
  max: 30,
  standardHeaders: true,
  legacyHeaders: false
});

const apiLimiter = rateLimit({
  windowMs: 1 * 60 * 1000,
  max: 300,
  standardHeaders: true,
  legacyHeaders: false
});

app.use('/api/', apiLimiter);

// ---- Authentication Middleware ----

function jwtAuth(req: AuthenticatedRequest, res: Response, next: NextFunction) {
  const header = req.header('Authorization');
  if (!header?.startsWith('Bearer ')) {
    return res.status(401).json({ message: 'Unauthorized' });
  }

  const token = header.slice('Bearer '.length);

  try {
    const decoded = jwt.verify(token, JWT_PUBLIC_KEY) as { sub: string; role: GlobalRole };
    req.user = {
      id: decoded.sub,
      globalRole: decoded.role
    };
    return next();
  } catch (err) {
    console.warn('Auth failure', { error: (err as Error).message });
    return res.status(401).json({ message: 'Invalid token' });
  }
}

app.use(jwtAuth);

// ---- Authorization Helpers ----

// Global role check
function requireGlobalRole(allowed: GlobalRole[]) {
  return (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
    if (!req.user) return res.status(401).json({ message: 'Unauthorized' });

    if (!allowed.includes(req.user.globalRole)) {
      console.warn('Global RBAC denied', {
        userId: req.user.id,
        role: req.user.globalRole,
        path: req.path,
        method: req.method
      });
      return res.status(403).json({ message: 'Forbidden' });
    }

    return next();
  };
}

// Resource-scoped project permission check
async function checkProjectPermission(
  userId: string,
  projectId: string,
  requiredRoles: ProjectRole[]
): Promise<boolean> {
  const membership = await projectRepo.getMembership(userId, projectId);
  if (!membership) return false;
  return requiredRoles.includes(membership.role);
}

function requireProjectRole(requiredRoles: ProjectRole[]) {
  return async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
    if (!req.user) return res.status(401).json({ message: 'Unauthorized' });

    const projectId = req.params.projectId;
    if (!projectId) {
      return res.status(400).json({ message: 'Missing projectId' });
    }

    try {
      const allowed = await checkProjectPermission(req.user.id, projectId, requiredRoles);

      // Allow system admins as break-glass (policy decision)
      const isSystemAdmin = req.user.globalRole === 'system_admin';

      if (!allowed && !isSystemAdmin) {
        console.warn('Project RBAC denied', {
          userId: req.user.id,
          globalRole: req.user.globalRole,
          projectId,
          requiredRoles,
          path: req.path
        });
        return res.status(403).json({ message: 'Forbidden' });
      }

      return next();
    } catch (err) {
      console.error('Error checking project permissions', err);
      return res.status(500).json({ message: 'Internal server error' });
    }
  };
}

// ---- Routes ----

// Global admin: manage any project (with strict rate limiting)
app.post(
  '/api/admin/projects/:projectId/lock',
  adminLimiter,
  requireGlobalRole(['system_admin']),
  async (req: AuthenticatedRequest, res: Response) => {
    const projectId = req.params.projectId;
    try {
      // Lock project in DB (pseudo)
      console.info('Project locked', { projectId, by: req.user?.id });
      return res.json({ message: `Project ${projectId} locked` });
    } catch (err) {
      console.error('Error locking project', err);
      return res.status(500).json({ message: 'Internal server error' });
    }
  }
);

// Project-scoped admin/editor can modify project details
app.put(
  '/api/projects/:projectId',
  requireProjectRole(['project_owner', 'project_admin', 'project_editor']),
  async (req: AuthenticatedRequest, res: Response) => {
    const projectId = req.params.projectId;
    const { name } = req.body;

    if (typeof name !== 'string' || name.length < 3) {
      return res.status(400).json({ message: 'Invalid project name' });
    }

    try {
      // Update project name in DB (pseudo)
      console.info('Project updated', { projectId, by: req.user?.id });
      return res.json({ id: projectId, name });
    } catch (err) {
      console.error('Error updating project', err);
      return res.status(500).json({ message: 'Internal server error' });
    }
  }
);

// Project viewers and above can read project
app.get(
  '/api/projects/:projectId',
  requireProjectRole(['project_owner', 'project_admin', 'project_editor', 'project_viewer']),
  async (req: AuthenticatedRequest, res: Response) => {
    const projectId = req.params.projectId;
    try {
      // Fetch project details
      const project = { id: projectId, name: 'Demo Project' };
      console.info('Project viewed', { projectId, by: req.user?.id });
      return res.json(project);
    } catch (err) {
      console.error('Error fetching project', err);
      return res.status(500).json({ message: 'Internal server error' });
    }
  }
);

// ---- Security Headers & Error Handling ----

app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '0');
  if (ENV === 'production') {
    res.setHeader('Content-Security-Policy', "default-src 'none'; frame-ancestors 'none';");
  }
  return next();
});

// Central error handler (fallback)
app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
  console.error('Unhandled error', err);
  return res.status(500).json({ message: 'Internal server error' });
});

const PORT = process.env.PORT || 4000;
app.listen(PORT, () => {
  console.log(`Production-style API listening on port ${PORT} in ${ENV} mode`);
});
```

**Defense in Depth Layers**:
1. **Authentication + Strong Identity**: JWT-based `jwtAuth` middleware ensures every request gets a verified identity (`user.id`, `globalRole`) before any authorization decisions.
2. **Global RBAC + Resource-Scoped Permissions**: `requireGlobalRole` for platform-wide actions (like locking any project), and `requireProjectRole` for per-project permissions using a repository layer and membership table.
3. **Operational Controls (Rate limiting, logging, and headers)**: Route-specific rate limiting for admin operations, structured logging for access denials and changes, and security headers to reduce browser attack surface if responses are consumed by web clients.

**Additional Protections**:
- **Centralized policy store**: Move role and permission rules into a dedicated policy module or external policy engine (e.g., Open Policy Agent) to avoid scattered, inconsistent checks.
- **Audit logging and monitoring**: Ship logs to a SIEM; create alerts for suspicious patterns (e.g., repeated 403s from the same user/IP, system_admin actions outside business hours).
- **Least privilege and break-glass procedures**: Assign minimal necessary project roles by default, restrict `system_admin` accounts, and enforce additional verification (MFA, just-in-time elevation) for highly sensitive operations.

Missing or incorrect attribute-based access control (ABAC) is a common cause of multi-tenant data leaks. A frequent mistake is only checking that a user is authenticated, or only checking their role, without verifying resource attributes like `tenantId`, `ownerId`, or environment (prod vs test).

**VULNERABLE CODE**:

```typescript
import express, { Request, Response, NextFunction } from 'express';

interface UserTokenPayload {
  id: string;
  role: 'user' | 'admin' | 'support';
  tenantId: string;
}

interface AuthedRequest extends Request {
  user?: UserTokenPayload;
}

// Simulated in-memory data
const documents = [
  { id: 'doc-1', tenantId: 'tenant-a', ownerId: 'user-1', content: 'Secret A1' },
  { id: 'doc-2', tenantId: 'tenant-b', ownerId: 'user-2', content: 'Secret B1' },
];

const app = express();

// Fake auth middleware (assume user is already set by earlier middleware)
function requireAuth(req: AuthedRequest, res: Response, next: NextFunction) {
  if (!req.user) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  next();
}

// VULNERABLE: only checks role, not tenant or document attributes
app.get('/api/documents/:id', requireAuth, (req: AuthedRequest, res: Response) => {
  const { id } = req.params;
  const doc = documents.find(d => d.id === id);

  if (!doc) {
    return res.status(404).json({ error: 'Not found' });
  }

  // BUG: Any support user can read ANY tenant's documents
  if (req.user!.role === 'support' || req.user!.id === doc.ownerId) {
    return res.json({ id: doc.id, content: doc.content, tenantId: doc.tenantId });
  }

  // BUG: Missing tenantId comparison, cross-tenant access for admins
  if (req.user!.role === 'admin') {
    return res.json({ id: doc.id, content: doc.content, tenantId: doc.tenantId });
  }

  return res.status(403).json({ error: 'Forbidden' });
});

app.listen(3000, () => {
  console.log('Server running on http://localhost:3000');
});
```

**Attack Payload** (HTTP request):
```bash
curl -H "Authorization: Bearer <support_or_admin_token_for_tenant-a>" \
  http://localhost:3000/api/documents/doc-2
```

This request uses a support or admin user from `tenant-a` to access `doc-2` that belongs to `tenant-b`, which should be forbidden in a strict multi-tenant model.

**Why This Is Dangerous**:
- Cross-tenant data leakage: roles are checked, but resource `tenantId` is ignored.
- Over-privileged support/admin users can access any tenant's documents.
- No central policy: ABAC rules are scattered and easy to get wrong or forget.

**SECURE VERSION**:

```typescript
import express, { Request, Response, NextFunction } from 'express';

interface UserTokenPayload {
  id: string;
  role: 'user' | 'admin' | 'support';
  tenantId: string;
  environment: 'prod' | 'test';
}

interface AuthedRequest extends Request {
  user?: UserTokenPayload;
}

interface Document {
  id: string;
  tenantId: string;
  ownerId: string;
  content: string;
  environment: 'prod' | 'test';
}

const documents: Document[] = [
  { id: 'doc-1', tenantId: 'tenant-a', ownerId: 'user-1', content: 'Secret A1', environment: 'prod' },
  { id: 'doc-2', tenantId: 'tenant-b', ownerId: 'user-2', content: 'Secret B1', environment: 'prod' },
];

const app = express();

// Centralized ABAC policy
function canReadDocument(user: UserTokenPayload, doc: Document): boolean {
  // 1) Basic tenant isolation: users may only see documents from their tenant
  if (user.tenantId !== doc.tenantId) {
    // Exception: limited support role can only access non-prod or via explicit delegation
    if (user.role === 'support' && doc.environment === 'test') {
      return true;
    }
    return false;
  }

  // 2) Environment restriction: support cannot access prod docs by default
  if (user.role === 'support' && doc.environment === 'prod') {
    return false;
  }

  // 3) Resource ownership
  if (user.role === 'user') {
    return user.id === doc.ownerId;
  }

  // 4) Tenant admin: full access within their tenant and allowed environment
  if (user.role === 'admin') {
    return true;
  }

  return false;
}

function requireAuth(req: AuthedRequest, res: Response, next: NextFunction) {
  if (!req.user) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  next();
}

app.get('/api/secure-documents/:id', requireAuth, (req: AuthedRequest, res: Response) => {
  const { id } = req.params;
  const user = req.user!;

  const doc = documents.find(d => d.id === id);
  if (!doc) {
    return res.status(404).json({ error: 'Not found' });
  }

  try {
    if (!canReadDocument(user, doc)) {
      console.warn(`Access denied: user=${user.id} tenant=${user.tenantId} doc=${doc.id} docTenant=${doc.tenantId}`);
      return res.status(403).json({ error: 'Forbidden' });
    }

    return res.json({ id: doc.id, content: doc.content });
  } catch (err) {
    console.error('Authorization error', err);
    return res.status(500).json({ error: 'Internal server error' });
  }
});

app.listen(3001, () => {
  console.log('Secure server running on http://localhost:3001');
});
```

**Key Security Controls**:
- Centralized ABAC policy function (`canReadDocument`) to consistently enforce tenant, environment, and ownership rules.
- Strict tenant isolation by comparing `user.tenantId` with `doc.tenantId`, with narrowly defined exceptions.
- Defense in depth with environment-based restrictions, ownership checks, and structured error handling and logging for denied access attempts.

For production, you want ABAC to be centralized, configurable, observable, and consistent across resource types. Instead of hardcoding rules in each route, you can implement a policy engine that evaluates JSON/YAML policies and supports attributes for user, action, resource, and environment.

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import fs from 'fs';
import path from 'path';

// ---- Types ----

type Role = 'user' | 'admin' | 'support' | 'auditor';

interface UserTokenPayload {
  id: string;
  role: Role;
  tenantId: string;
  environment: 'prod' | 'test';
  // Additional attributes
  scopes?: string[];
}

interface ResourceAttributes {
  type: 'document' | 'ticket' | 'user-profile';
  id: string;
  tenantId: string;
  ownerId?: string;
  environment: 'prod' | 'test';
}

interface PolicyRule {
  id: string;
  description: string;
  effect: 'allow' | 'deny';
  actions: string[]; // e.g. ["read", "write:content"]
  subject: {
    roles?: Role[];
    tenants?: string[] | ['*'];
    environments?: ('prod' | 'test')[];
    scopesAnyOf?: string[][]; // at least one array fully matches
  };
  resource: {
    types?: string[];
    tenantMustMatch?: boolean;
    ownerMustMatch?: boolean;
    environments?: ('prod' | 'test')[];
  };
}

interface PolicyConfig {
  rules: PolicyRule[];
  version: string;
}

interface AuthedRequest extends Request {
  user?: UserTokenPayload;
}

// ---- Simple in-memory policy loader with hot reload for dev ----

class PolicyEngine {
  private config: PolicyConfig;
  private readonly filePath: string;

  constructor(filePath: string) {
    this.filePath = filePath;
    this.config = this.loadFromDisk();

    if (process.env.NODE_ENV !== 'production') {
      fs.watchFile(this.filePath, () => {
        console.log('[PolicyEngine] Reloading policies from disk');
        this.config = this.loadFromDisk();
      });
    }
  }

  private loadFromDisk(): PolicyConfig {
    const raw = fs.readFileSync(this.filePath, 'utf8');
    const parsed = JSON.parse(raw) as PolicyConfig;
    console.log(`[PolicyEngine] Loaded policy version ${parsed.version}`);
    return parsed;
  }

  public evaluate(action: string, user: UserTokenPayload, resource: ResourceAttributes): boolean {
    const { rules } = this.config;

    let allow = false;

    for (const rule of rules) {
      if (!rule.actions.includes(action)) continue;

      // Subject match
      if (rule.subject.roles && !rule.subject.roles.includes(user.role)) continue;
      if (rule.subject.tenants && !rule.subject.tenants.includes('*') && !rule.subject.tenants.includes(user.tenantId)) continue;
      if (rule.subject.environments && !rule.subject.environments.includes(user.environment)) continue;

      if (rule.subject.scopesAnyOf && user.scopes) {
        const hasScopes = rule.subject.scopesAnyOf.some(requiredSet =>
          requiredSet.every(scope => user.scopes!.includes(scope))
        );
        if (!hasScopes) continue;
      } else if (rule.subject.scopesAnyOf && !user.scopes) {
        continue;
      }

      // Resource match
      if (rule.resource.types && !rule.resource.types.includes(resource.type)) continue;
      if (rule.resource.environments && !rule.resource.environments.includes(resource.environment)) continue;
      if (rule.resource.tenantMustMatch && user.tenantId !== resource.tenantId) continue;
      if (rule.resource.ownerMustMatch && resource.ownerId && user.id !== resource.ownerId) continue;

      // Rule matches; apply effect
      if (rule.effect === 'deny') {
        console.warn(`[PolicyEngine] Deny by rule ${rule.id}`);
        return false;
      }
      if (rule.effect === 'allow') {
        console.debug(`[PolicyEngine] Allow by rule ${rule.id}`);
        allow = true;
        // continue evaluation; later deny could override if using deny-first model
      }
    }

    return allow;
  }
}

// ---- App & Middleware ----

const app = express();
const policyPath = path.join(__dirname, 'abac-policies.json');
const policyEngine = new PolicyEngine(policyPath);

// Example resources in-memory
const documents: ResourceAttributes[] = [
  { type: 'document', id: 'doc-1', tenantId: 'tenant-a', ownerId: 'user-1', environment: 'prod' },
  { type: 'document', id: 'doc-2', tenantId: 'tenant-b', ownerId: 'user-2', environment: 'prod' },
];

function requireAuth(req: AuthedRequest, res: Response, next: NextFunction) {
  if (!req.user) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  next();
}

// Generic authorization middleware factory
function authorize(action: string, getResource: (req: AuthedRequest) => ResourceAttributes | null) {
  return (req: AuthedRequest, res: Response, next: NextFunction) => {
    const user = req.user!;
    const resource = getResource(req);
    if (!resource) {
      return res.status(404).json({ error: 'Not found' });
    }

    const allowed = policyEngine.evaluate(action, user, resource);
    if (!allowed) {
      console.warn(`Access denied: user=${user.id} tenant=${user.tenantId} action=${action} resource=${resource.type}:${resource.id}`);
      return res.status(403).json({ error: 'Forbidden' });
    }

    // Audit log success
    console.info(`Access granted: user=${user.id} action=${action} resource=${resource.type}:${resource.id}`);
    next();
  };
}

// Example route using generic ABAC middleware
app.get(
  '/api/v2/documents/:id',
  requireAuth,
  authorize('read', (req: AuthedRequest) => {
    const id = req.params.id;
    return documents.find(d => d.id === id) || null;
  }),
  (req: AuthedRequest, res: Response) => {
    const id = req.params.id;
    const doc = documents.find(d => d.id === id);
    if (!doc) {
      return res.status(404).json({ error: 'Not found' });
    }
    return res.json({ id: doc.id, tenantId: doc.tenantId, environment: doc.environment });
  }
);

// Basic security headers & rate-limiting placeholder (use libraries in real apps)
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  next();
});

// Environment-specific configuration
const PORT = process.env.PORT || 3002;
if (process.env.NODE_ENV === 'production') {
  console.log('Running in production mode: enabling stricter logging');
}

// Global error handler
app.use((err: Error, req: Request, res: Response, _next: NextFunction) => {
  console.error('Unhandled error', err.message);
  res.status(500).json({ error: 'Internal server error' });
});

app.listen(PORT, () => {
  console.log(`ABAC API running on http://localhost:${PORT}`);
});
```

