**Attack Payload** (if applicable):
```bash
# Attacker is logged in as user 1 but wants user 3's data
curl -H "Authorization: Bearer <valid-token-for-user-1>" \
  http://localhost:3000/api/users/3
```

**Why This Is Dangerous**:
- Any authenticated user can enumerate `/api/users/1`, `/api/users/2`, etc., and read other users' profiles.
- If the endpoint returns sensitive data (emails, billing info, tokens), this becomes a serious data breach.
- Lack of authorization checks violates least privilege and enables IDOR attacks similar to CVE-2023-1138-style access issues.

**SECURE VERSION**:

```typescript
import express, { Request, Response, NextFunction } from 'express';

const app = express();
app.use(express.json());

interface AuthUser {
  id: number;
  role: 'user' | 'admin';
}

interface UserRecord {
  id: number;
  email: string;
  plan: string;
}

const users: UserRecord[] = [
  { id: 1, email: 'alice@example.com', plan: 'pro' },
  { id: 2, email: 'bob@example.com', plan: 'free' },
  { id: 3, email: 'carol@example.com', plan: 'enterprise' }
];

// Simulated authentication middleware
function authMiddleware(req: Request, res: Response, next: NextFunction) {
  // In real life: verify JWT/session here.
  // For demo, assume user 1 (non-admin) is logged in.
  (req as any).user = { id: 1, role: 'user' } as AuthUser;
  next();
}

// Authorization helper: checks if requester can access a given userId
function canAccessUser(requester: AuthUser, targetUserId: number): boolean {
  // Allow admins to access any user
  if (requester.role === 'admin') {
    return true;
  }
  // Regular users can access only their own record
  return requester.id === targetUserId;
}

app.use(authMiddleware);

app.get('/api/users/:id', (req: Request, res: Response) => {
  const requester = (req as any).user as AuthUser;

  // Input validation
  const targetId = Number(req.params.id);
  if (!Number.isInteger(targetId) || targetId <= 0) {
    return res.status(400).json({ error: 'Invalid user ID' });
  }

  if (!canAccessUser(requester, targetId)) {
    // Log the attempt without leaking details
    console.warn(
      `Unauthorized access attempt: user ${requester.id} tried to access user ${targetId}`
    );
    return res.status(403).json({ error: 'Forbidden' });
  }

  const user = users.find(u => u.id === targetId);
  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }

  // Return only non-sensitive fields
  const safeResponse = {
    id: user.id,
    email: user.email,
    plan: user.plan
  };

  return res.json(safeResponse);
});

app.listen(3000, () => {
  console.log('Secure server running on port 3000');
});
```

**Key Security Controls**:
- Ownership & role checks: The `canAccessUser` function enforces that regular users only see their own data, while admins may see others when appropriate.
- Input validation: Strictly validates `:id` as a positive integer, reducing unexpected behavior and DoS-style abuse.
- Least data exposure: Returns only necessary, non-sensitive fields and logs unauthorized attempts without leaking implementation details.

In production, you want a reusable authorization layer that understands roles, ownership, and resource scopes, plus observability and rate limiting around sensitive endpoints.

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import rateLimit from 'express-rate-limit';

const app = express();
app.use(express.json());

// Environment-specific config
const isProd = process.env.NODE_ENV === 'production';

interface AuthUser {
  id: number;
  role: 'user' | 'admin' | 'support';
  orgId: number;
}

interface UserRecord {
  id: number;
  email: string;
  plan: string;
  orgId: number;
}

const users: UserRecord[] = [
  { id: 1, email: 'alice@example.com', plan: 'pro', orgId: 10 },
  { id: 2, email: 'bob@example.com', plan: 'free', orgId: 10 },
  { id: 3, email: 'carol@example.com', plan: 'enterprise', orgId: 20 }
];

// Basic auth simulation (replace with real JWT/session verification)
function authMiddleware(req: Request, res: Response, next: NextFunction) {
  try {
    // Example: user 2 is a support agent in org 10
    (req as any).user = { id: 2, role: 'support', orgId: 10 } as AuthUser;
    next();
  } catch (err) {
    console.error('Auth error:', err);
    return res.status(401).json({ error: 'Unauthorized' });
  }
}

// Central authorization decision function
function canAccessUser(
  requester: AuthUser,
  target: UserRecord,
  action: 'read' | 'update' | 'delete'
): boolean {
  // Admins can do anything within their org
  if (requester.role === 'admin' && requester.orgId === target.orgId) {
    return true;
  }

  // Support can read users in their org, but not update/delete
  if (requester.role === 'support') {
    return action === 'read' && requester.orgId === target.orgId;
  }

  // Regular users can only read/update their own profile (no delete in this example)
  if (requester.role === 'user') {
    if (requester.id === target.id && requester.orgId === target.orgId) {
      return action === 'read' || action === 'update';
    }
  }

  return false;
}

// Rate limiting for sensitive profile operations
const profileLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false
});

// Security headers (defense in depth)
app.use((req: Request, res: Response, next: NextFunction) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  if (isProd) {
    res.setHeader(
      'Content-Security-Policy',
      "default-src 'self'; frame-ancestors 'none'"
    );
  }
  next();
});

app.use(authMiddleware);

// Audit logging helper
function auditLog(message: string, meta: Record<string, unknown> = {}): void {
  const entry = {
    level: 'INFO',
    timestamp: new Date().toISOString(),
    message,
    ...meta
  };
  console.log(JSON.stringify(entry));
}

// GET user profile with robust authorization
app.get('/api/users/:id', profileLimiter, (req: Request, res: Response) => {
  const requester = (req as any).user as AuthUser;
  const targetId = Number(req.params.id);

  if (!Number.isInteger(targetId) || targetId <= 0) {
    return res.status(400).json({ error: 'Invalid user ID' });
  }

  const user = users.find(u => u.id === targetId);
  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }

  if (!canAccessUser(requester, user, 'read')) {
    auditLog('FORBIDDEN_PROFILE_READ', {
      requesterId: requester.id,
      requesterRole: requester.role,
      targetId,
      orgId: requester.orgId,
      ip: req.ip
    });
    return res.status(403).json({ error: 'Forbidden' });
  }

  auditLog('PROFILE_READ', {
    requesterId: requester.id,
    targetId,
    requesterRole: requester.role,
    orgId: requester.orgId
  });

  const safeResponse = {
    id: user.id,
    email: user.email,
    plan: user.plan
  };

  return res.json(safeResponse);
});

// UPDATE user profile with same authorization model
app.put('/api/users/:id', profileLimiter, (req: Request, res: Response) => {
  const requester = (req as any).user as AuthUser;
  const targetId = Number(req.params.id);

  if (!Number.isInteger(targetId) || targetId <= 0) {
    return res.status(400).json({ error: 'Invalid user ID' });
  }

  const userIndex = users.findIndex(u => u.id === targetId);
  if (userIndex === -1) {
    return res.status(404).json({ error: 'User not found' });
  }

  const targetUser = users[userIndex];

  if (!canAccessUser(requester, targetUser, 'update')) {
    auditLog('FORBIDDEN_PROFILE_UPDATE', {
      requesterId: requester.id,
      requesterRole: requester.role,
      targetId,
      orgId: requester.orgId,
      ip: req.ip
    });
    return res.status(403).json({ error: 'Forbidden' });
  }

  try {
    const { email, plan } = req.body as Partial<UserRecord>;

    // Simple validation
    if (email && typeof email !== 'string') {
      return res.status(400).json({ error: 'Invalid email' });
    }
    if (plan && typeof plan !== 'string') {
      return res.status(400).json({ error: 'Invalid plan' });
    }

    const updated: UserRecord = {
      ...targetUser,
      email: email ?? targetUser.email,
      plan: plan ?? targetUser.plan
    };

    users[userIndex] = updated;

    auditLog('PROFILE_UPDATE', {
      requesterId: requester.id,
      targetId,
      requesterRole: requester.role,
      orgId: requester.orgId
    });

    return res.json({ id: updated.id, email: updated.email, plan: updated.plan });
  } catch (err) {
    console.error('Update error:', err);
    return res.status(500).json({ error: 'Internal server error' });
  }
});

app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
  console.error('Unhandled error:', err);
  res.status(500).json({ error: 'Internal server error' });
});

app.listen(3000, () => {
  console.log(`Server running in ${isProd ? 'production' : 'development'} mode on port 3000`);
});
```

**Defense in Depth Layers**:
1. Authorization service layer:
   - Central `canAccessUser` function enforces ownership, org boundaries, and role-specific permissions for every action:
   ```typescript
   if (!canAccessUser(requester, user, 'read')) {
     return res.status(403).json({ error: 'Forbidden' });
   }
   ```
2. Rate limiting & input validation:
   - `profileLimiter` restricts abusive access patterns, while strict ID and body validation reduce attack surface:
   ```typescript
   if (!Number.isInteger(targetId) || targetId <= 0) {
     return res.status(400).json({ error: 'Invalid user ID' });
   }
   ```
3. Monitoring & audit logging:
   - Structured logs capture both successful and denied access for anomaly detection and forensics:
   ```typescript
   auditLog('FORBIDDEN_PROFILE_READ', {
     requesterId: requester.id,
     requesterRole: requester.role,
     targetId,
     orgId: requester.orgId,
     ip: req.ip
   });
   ```

**Additional Protections**:
- Environment-specific security headers (CSP, X-Frame-Options, etc.) to mitigate client-side exploitation if any data is reflected to browsers.
- Consistent error handling that avoids leaking internal details while still signaling unauthorized vs. bad input vs. server errors.
- Clear separation between authentication, authorization, and business logic, allowing you to swap in a dedicated policy engine or external authorization service without rewriting handlers.

When building file upload endpoints, a common mistake is to only check that the user is logged in and forget to verify that they are allowed to upload to a specific project or path. That leads to broken access control and potential arbitrary file overwrite.

**VULNERABLE CODE**:

```typescript
import express, { Request, Response } from 'express';
import multer from 'multer';
import path from 'path';
import fs from 'fs';

const app = express();
const upload = multer({ dest: 'uploads/' });

// Fake middleware: only checks that user is authenticated
function requireAuth(req: Request, res: Response, next: () => void) {
  if (!req.headers['x-user-id']) {
    return res.status(401).json({ error: 'Not authenticated' });
  }
  // In reality you would load the user from DB, but we just attach an ID
  (req as any).user = { id: req.headers['x-user-id'] };
  next();
}

// VULNERABLE: any authenticated user can upload to any project and overwrite files
app.post('/api/projects/:projectId/upload', requireAuth, upload.single('file'), (req: Request, res: Response) => {
  const projectId = req.params.projectId; // no authorization check
  const file = req.file;

  if (!file) {
    return res.status(400).json({ error: 'No file uploaded' });
  }

  // Directly trust projectId for file path
  const targetDir = path.join(__dirname, 'project_files', projectId);
  if (!fs.existsSync(targetDir)) {
    fs.mkdirSync(targetDir, { recursive: true });
  }

  const targetPath = path.join(targetDir, file.originalname);

  fs.renameSync(file.path, targetPath); // may overwrite existing file

  res.json({ message: 'File uploaded', path: targetPath });
});

app.listen(3000, () => {
  console.log('Server started on port 3000');
});
```

**Attack Payload** (HTTP request exploiting authorization flaw):
```bash
curl -X POST "http://localhost:3000/api/projects/12345/upload" \
  -H "x-user-id: attacker" \
  -F "file=@/tmp/malicious-config.yml;filename=config.yml"
```

This payload assumes that project `12345` belongs to another user. The attacker can overwrite `config.yml` or other sensitive files for that project just by being authenticated.

**Why This Is Dangerous**:
- Any authenticated user can upload or overwrite files for any project ID (insecure direct object reference).
- There is no check that the user is a member/owner of the project, or that they have upload permissions.
- The server trusts user-controlled identifiers (`projectId` and `originalname`) in file system paths, which may lead to overwrites and chaining with other vulnerabilities.

**SECURE VERSION**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import multer from 'multer';
import path from 'path';
import fs from 'fs';

const app = express();
const upload = multer({ dest: 'uploads/' });

interface User {
  id: string;
  role: 'user' | 'admin';
}

interface Project {
  id: string;
  ownerId: string;
  members: string[];
  uploadsEnabled: boolean;
}

// Simulated project store
const projects: Project[] = [
  { id: '1', ownerId: 'u1', members: ['u1', 'u2'], uploadsEnabled: true },
  { id: '2', ownerId: 'u3', members: ['u3'], uploadsEnabled: false }
];

function findProjectById(id: string): Project | undefined {
  return projects.find(p => p.id === id);
}

function requireAuth(req: Request, res: Response, next: NextFunction) {
  const userId = req.headers['x-user-id'];
  if (!userId || typeof userId !== 'string') {
    return res.status(401).json({ error: 'Not authenticated' });
  }
  (req as any).user = { id: userId, role: 'user' } as User;
  next();
}

// Authorization middleware: check user is member/owner and uploads allowed
function requireProjectUploadPermission(req: Request, res: Response, next: NextFunction) {
  const user = (req as any).user as User | undefined;
  const projectId = req.params.projectId;

  if (!user) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  const project = findProjectById(projectId);

  if (!project) {
    return res.status(404).json({ error: 'Project not found' });
  }

  const isMember = project.members.includes(user.id);
  const isOwner = project.ownerId === user.id;

  if (!isMember && user.role !== 'admin') {
    return res.status(403).json({ error: 'Not authorized to upload to this project' });
  }

  if (!project.uploadsEnabled && user.role !== 'admin') {
    return res.status(403).json({ error: 'Uploads are disabled for this project' });
  }

  // Attach project to request for later handlers
  (req as any).project = project;
  next();
}

// Simple filename whitelist (defense-in-depth)
function sanitizeFilename(filename: string): string {
  const base = path.basename(filename); // remove any directory components
  // Only allow alphanumerics, dash, underscore, dot
  return base.replace(/[^a-zA-Z0-9._-]/g, '_');
}

app.post(
  '/api/projects/:projectId/upload',
  requireAuth,
  requireProjectUploadPermission,
  upload.single('file'),
  (req: Request, res: Response) => {
    const user = (req as any).user as User;
    const project = (req as any).project as Project;
    const file = req.file;

    if (!file) {
      return res.status(400).json({ error: 'No file uploaded' });
    }

    try {
      const safeFilename = sanitizeFilename(file.originalname);
      const targetDir = path.join(__dirname, 'project_files', project.id);

      if (!fs.existsSync(targetDir)) {
        fs.mkdirSync(targetDir, { recursive: true });
      }

      const targetPath = path.join(targetDir, safeFilename);

      // Avoid silent overwrite: if file exists, require explicit replace flag
      const allowReplace = req.query.replace === 'true';
      if (fs.existsSync(targetPath) && !allowReplace) {
        fs.unlinkSync(file.path); // delete temp file
        return res.status(409).json({
          error: 'File already exists. Use ?replace=true to overwrite.'
        });
      }

      fs.renameSync(file.path, targetPath);

      console.log(
        `User ${user.id} uploaded file ${safeFilename} to project ${project.id}`
      );

      res.json({
        message: 'File uploaded',
        projectId: project.id,
        filename: safeFilename
      });
    } catch (err) {
      console.error('Upload error:', err);
      if (req.file && fs.existsSync(req.file.path)) {
        fs.unlinkSync(req.file.path);
      }
      res.status(500).json({ error: 'Internal server error' });
    }
  }
);

app.listen(3000, () => {
  console.log('Secure upload server started on port 3000');
});
```

**Key Security Controls**:
- **Project-level authorization checks**: `requireProjectUploadPermission` verifies that the user is a project member/owner (or admin) and that uploads are enabled before allowing file writes.
- **Path and filename hardening**: `sanitizeFilename` removes directory traversal attempts and limits filenames to a safe character set, preventing path manipulation.
- **Controlled overwrite behavior with logging**: The handler prevents silent overwrites unless the client explicitly opts in (`?replace=true`), and logs who uploaded which file to which project for auditability and incident response.

In production, you should centralize authorization logic, separate metadata from storage, and add multiple protection layers: strict RBAC, size/type limits, rate limiting, secure storage, and audit logging that can feed monitoring systems.

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import multer from 'multer';
import path from 'path';
import fs from 'fs';
import crypto from 'crypto';

// In real systems use a proper logger and monitoring (e.g., pino + Prometheus)
const app = express();

// Environment-specific config
const ENV = process.env.NODE_ENV || 'development';
const MAX_FILE_SIZE_MB = ENV === 'production' ? 50 : 5;
const MAX_FILE_SIZE = MAX_FILE_SIZE_MB * 1024 * 1024;

// Simple in-memory rate limit store (replace with Redis or similar in prod)
const uploadAttempts: Record<string, { count: number; resetAt: number }> = {};

interface User {
  id: string;
  role: 'user' | 'manager' | 'admin';
}

interface Project {
  id: string;
  ownerId: string;
  members: string[];
  managers: string[];
  uploadsEnabled: boolean;
}

const projects: Project[] = [
  {
    id: '1',
    ownerId: 'u1',
    members: ['u1', 'u2', 'u4'],
    managers: ['u2'],
    uploadsEnabled: true
  }
];

function findProject(id: string): Project | undefined {
  return projects.find(p => p.id === id);
}

function logAudit(event: string, details: Record<string, unknown>): void {
  const entry = {
    ts: new Date().toISOString(),
    event,
    ...details
  };
  console.log('[AUDIT]', JSON.stringify(entry));
}

function requireAuth(req: Request, res: Response, next: NextFunction) {
  const userId = req.headers['x-user-id'];
  const role = (req.headers['x-role'] as string) || 'user';

  if (!userId || typeof userId !== 'string') {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  const user: User = { id: userId, role: role as User['role'] };
  (req as any).user = user;
  next();
}

// Role & project-based authorization
function requireProjectUploadPermission(req: Request, res: Response, next: NextFunction) {
  const user = (req as any).user as User | undefined;
  const projectId = req.params.projectId;

  if (!user) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  const project = findProject(projectId);
  if (!project) {
    return res.status(404).json({ error: 'Project not found' });
  }

  const isOwner = project.ownerId === user.id;
  const isManager = project.managers.includes(user.id);
  const isMember = project.members.includes(user.id);

  const canUpload =
    user.role === 'admin' ||
    isOwner ||
    isManager ||
    (isMember && project.uploadsEnabled);

  if (!canUpload) {
    logAudit('upload_denied', {
      userId: user.id,
      projectId: project.id,
      reason: 'insufficient_permissions'
    });
    return res.status(403).json({ error: 'Not authorized to upload to this project' });
  }

  (req as any).project = project;
  next();
}

// Rate limiting per user (very simple variant)
function uploadRateLimit(req: Request, res: Response, next: NextFunction) {
  const user = (req as any).user as User | undefined;
  if (!user) return res.status(401).json({ error: 'Not authenticated' });

  const key = user.id;
  const now = Date.now();
  const windowMs = 15 * 60 * 1000; // 15 minutes
  const maxUploads = ENV === 'production' ? 50 : 1000;

  let bucket = uploadAttempts[key];
  if (!bucket || bucket.resetAt < now) {
    bucket = { count: 0, resetAt: now + windowMs };
    uploadAttempts[key] = bucket;
  }

  if (bucket.count >= maxUploads) {
    logAudit('upload_rate_limited', { userId: user.id });
    return res.status(429).json({ error: 'Too many upload attempts, slow down' });
  }

  bucket.count++;
  next();
}

// Multer config with strict limits
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, 'tmp_uploads/');
  },
  filename: (req, file, cb) => {
    const randomName = crypto.randomBytes(16).toString('hex');
    cb(null, randomName + path.extname(file.originalname));
  }
});

const upload = multer({
  storage,
  limits: {
    fileSize: MAX_FILE_SIZE
  },
  fileFilter: (req, file, cb) => {
    // Allow only a few safe mime types (example)
    const allowed = ['image/png', 'image/jpeg', 'application/pdf'];
    if (!allowed.includes(file.mimetype)) {
      return cb(new Error('Unsupported file type'));
    }
    cb(null, true);
  }
});

function sanitizeFilename(original: string): string {
  const base = path.basename(original);
  return base.replace(/[^a-zA-Z0-9._-]/g, '_');
}

app.post(
  '/api/projects/:projectId/upload',
  requireAuth,
  uploadRateLimit,
  requireProjectUploadPermission,
  upload.single('file'),
  (req: Request, res: Response) => {
    const user = (req as any).user as User;
    const project = (req as any).project as Project;
    const file = req.file;

    if (!file) {
      return res.status(400).json({ error: 'No file uploaded' });
    }

    const originalName = sanitizeFilename(file.originalname);
    const targetDir = path.join(__dirname, 'project_files', project.id);
    const targetPath = path.join(targetDir, originalName);

    try {
      if (!fs.existsSync(targetDir)) {
        fs.mkdirSync(targetDir, { recursive: true });
      }

      const allowReplace = req.query.replace === 'true';
      const exists = fs.existsSync(targetPath);

      if (exists && !allowReplace) {
        fs.unlinkSync(file.path);
        logAudit('upload_conflict', {
          userId: user.id,
          projectId: project.id,
          filename: originalName
        });
        return res.status(409).json({
          error: 'File already exists. Use ?replace=true to overwrite.'
        });
      }

      // Move from temp storage to project storage
      fs.renameSync(file.path, targetPath);

      logAudit('upload_success', {
        userId: user.id,
        projectId: project.id,
        filename: originalName,
        size: file.size,
        mimetype: file.mimetype
      });

      res.status(exists ? 200 : 201).json({
        message: exists ? 'File replaced' : 'File uploaded',
        projectId: project.id,
        filename: originalName
      });
    } catch (err) {
      console.error('Upload error:', err);
      logAudit('upload_error', {
        userId: user.id,
        projectId: project.id,
        error: (err as Error).message
      });

      if (file && fs.existsSync(file.path)) {
        fs.unlinkSync(file.path);
      }
      res.status(500).json({ error: 'Internal server error' });
    }
  }
);

// Basic security headers (for a full web app you would add more)
app.use((req: Request, res: Response, next: NextFunction) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  next();
});

app.listen(3000, () => {
  console.log(`Prod-style upload server listening on 3000 (env=${ENV})`);
});
```

**Defense in Depth Layers**:
1. **Centralized RBAC and project checks**:
   ```typescript
   const canUpload =
     user.role === 'admin' ||
     isOwner ||
     isManager ||
     (isMember && project.uploadsEnabled);
   if (!canUpload) {
     return res.status(403).json({ error: 'Not authorized' });
   }
   ```
   This enforces role- and project-based permissions before any file system operations.

2. **Resource and abuse controls (limits + rate limiting)**:
   ```typescript
   const upload = multer({ limits: { fileSize: MAX_FILE_SIZE } });
   if (bucket.count >= maxUploads) {
     return res.status(429).json({ error: 'Too many upload attempts' });
   }
   ```
   This prevents oversized uploads and brute-force/DoS via upload spam.

3. **Audit logging and monitoring hooks**:
   ```typescript
   logAudit('upload_success', {
     userId: user.id,
     projectId: project.id,
     filename: originalName,
     size: file.size
   });
   ```
   These logs provide traceability for every upload attempt and outcome, feeding into SIEM/monitoring.

**Additional Protections**:
- **Store only metadata in the DB and files in object storage** (e.g., S3 with per-project buckets and explicit IAM policies) to isolate file access from app server compromise.
- **Background virus/malware scanning** of uploaded files before they are made available to others, with quarantine and notification workflows.
- **Strict content-type and download controls** (set `Content-Disposition: attachment` and do not serve user uploads from the same domain as your main app) to reduce XSS and drive-by download risks.

Missing or weak RBAC checks in APIs lead directly to broken access control. An attacker with any valid token (or a compromised low-privilege account) can perform admin operations if the server only "trusts" client-supplied role data or forgets to check roles at all.

**VULNERABLE CODE**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';

const app = express();
app.use(express.json());

// Fake secret for demo only
const JWT_SECRET = 'dev-secret-change-me';

// Vulnerable auth middleware: blindly trusts JWT payload and client-supplied role
function authMiddleware(req: Request, res: Response, next: NextFunction) {
  const token = req.headers.authorization?.replace('Bearer ', '');
  if (!token) {
    return res.status(401).json({ error: 'Missing token' });
  }

  try {
    const decoded: any = jwt.verify(token, JWT_SECRET);

    // VULNERABLE: trusts role from token without server-side validation
    // and even allows overriding via request body
    (req as any).user = {
      id: decoded.sub,
      role: (req.body && req.body.role) || decoded.role || 'user'
    };

    next();
  } catch (err) {
    return res.status(401).json({ error: 'Invalid token' });
  }
}

// Critical admin endpoint
app.post('/api/admin/users/:id/disable', authMiddleware, (req: Request, res: Response) => {
  const user = (req as any).user;

  // VULNERABLE: only checks a string compare that attacker can control
  if (user.role !== 'admin') {
    return res.status(403).json({ error: 'Admins only' });
  }

  const targetUserId = req.params.id;
  // Imagine: update database to disable this account
  console.log(`Disabling user ${targetUserId}`);

  return res.json({ status: 'disabled', targetUserId });
});

app.listen(3000, () => {
  console.log('Server running on http://localhost:3000');
});
```

**Attack Payload** (JWT tampering + body override):
```text
1) Attacker steals any valid user JWT or signs one with a guessed dev secret.

2) Sends request:

POST /api/admin/users/123/disable
Authorization: Bearer <valid-or-forged-user-token>
Content-Type: application/json

{
  "role": "admin"   // overrides trusted role in vulnerable middleware
}
```

**Why This Is Dangerous**:
- Relies on **untrusted client input** (`req.body.role`) to decide admin vs user
- Treats role in JWT as **ground truth** without checking against a server-side source
- No defense against **privilege escalation** if JWT secret leaks or a low-privilege token is compromised

**SECURE VERSION**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import jwt, { JwtPayload } from 'jsonwebtoken';

const app = express();
app.use(express.json());

// In production, load from environment variable or secret manager
const JWT_SECRET = process.env.JWT_SECRET || 'dev-secret-change-me';

// Example of roles stored server-side (e.g., DB or user service)
interface UserRecord {
  id: string;
  role: 'user' | 'admin' | 'support';
  isDisabled: boolean;
}

// Fake in-memory user store instead of trusting client
const users: Record<string, UserRecord> = {
  '1': { id: '1', role: 'admin', user: 'user', isDisabled: false } as any
};

// Extend Express Request type for TypeScript safety
interface AuthenticatedRequest extends Request {
  user?: UserRecord;
}

function authMiddleware(req: AuthenticatedRequest, res: Response, next: NextFunction) {
  const token = req.headers.authorization?.replace('Bearer ', '');
  if (!token) {
    return res.status(401).json({ error: 'Missing token' });
  }

  try {
    const decoded = jwt.verify(token, JWT_SECRET) as JwtPayload;
    const userId = decoded.sub as string;

    // PRIMARY DEFENSE: Look up role server-side, never from client-provided data
    const user = users[userId];
    if (!user || user.isDisabled) {
      return res.status(403).json({ error: 'Account not allowed' });
    }

    req.user = user;
    next();
  } catch (err) {
    console.error('JWT verification failed', err);
    return res.status(401).json({ error: 'Invalid token' });
  }
}

// Reusable RBAC middleware factory
function requireRole(...allowedRoles: Array<UserRecord['role']>) {
  return (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
    if (!req.user) {
      return res.status(401).json({ error: 'Not authenticated' });
    }

    // PRIMARY DEFENSE: Enforce role membership on server
    if (!allowedRoles.includes(req.user.role)) {
      console.warn(`RBAC denied: user=${req.user.id} role=${req.user.role}`);
      return res.status(403).json({ error: 'Forbidden' });
    }

    next();
  };
}

// Secure admin endpoint with strict RBAC
app.post(
  '/api/admin/users/:id/disable',
  authMiddleware,
  requireRole('admin'),
  (req: AuthenticatedRequest, res: Response) => {
    const targetUserId = req.params.id;

    // DEFENSE IN DEPTH: Validate target exists and prevent self-lockout logic, etc.
    const target = users[targetUserId];
    if (!target) {
      return res.status(404).json({ error: 'User not found' });
    }

    if (target.id === req.user!.id) {
      return res.status(400).json({ error: 'Cannot disable own account' });
    }

    target.isDisabled = true;

    console.log(`Admin ${req.user!.id} disabled user ${targetUserId}`);
    return res.json({ status: 'disabled', targetUserId });
  }
);

// Safe user endpoint with basic check (example)
app.get('/api/me', authMiddleware, (req: AuthenticatedRequest, res: Response) => {
  return res.json({ user: req.user });
});

app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
  console.error('Unexpected error', err);
  res.status(500).json({ error: 'Internal server error' });
});

app.listen(3000, () => {
  console.log('Secure RBAC server running on http://localhost:3000');
});
```

**Key Security Controls**:
- **Server-side role lookup**: Authorization relies on roles stored on the server (DB or user service), not on request body or untrusted JWT claims, preventing trivial role escalation.
- **Reusable RBAC middleware**: `requireRole` centralizes authorization rules, reduces "forgot to check" mistakes, and makes policies explicit and testable.
- **Secure error handling and logging**: Returns generic error messages to clients while logging details on the server for monitoring and incident response, without leaking sensitive info.

For production-grade RBAC you should avoid scattering role checks across handlers and instead centralize authorization with a policy engine or permission map. Combine role-based and permission-based checks, environment-specific config, structured audit logs, and rate limiting around sensitive operations.

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import jwt, { JwtPayload } from 'jsonwebtoken';
import rateLimit from 'express-rate-limit';
import helmet from 'helmet';

// --- Types & Models ---

interface User {
  id: string;
  roles: string[]; // e.g., ['admin', 'support']
  isDisabled: boolean;
}

interface AuthenticatedRequest extends Request {
  user?: User;
}

// Permission model: role -> permissions
// In production, load from config/DB instead of hardcoding
const ROLE_PERMISSIONS: Record<string, string[]> = {
  admin: ['user:read', 'user:disable', 'user:enable', 'audit:read'],
  support: ['user:read'],
  auditor: ['audit:read']
};

// Example in-memory store; replace with DB in real apps
const users: Record<string, User> = {
  '1': { id: '1', roles: ['admin'], isDisabled: false },
  '2': { id: '2', roles: ['support'], isDisabled: false }
};

// --- Config & App Setup ---

const app = express();
app.use(express.json());
app.use(helmet()); // Security headers: XSS, clickjacking, etc.

// Environment-specific configuration
const isProd = process.env.NODE_ENV === 'production';
const JWT_SECRET = process.env.JWT_SECRET || 'dev-secret-change-me';

// Rate limiting particularly sensitive endpoints
const sensitiveLimiter = rateLimit({
  windowMs: 5 * 60 * 1000,
  max: 20,
  standardHeaders: true,
  legacyHeaders: false
});

// --- Logging & Audit ---

function auditLog(event: string, details: Record<string, unknown>): void {
  // In production, send to SIEM/centralized logging with request ID, etc.
  console.log(JSON.stringify({
    ts: new Date().toISOString(),
    event,
    ...details
  }));
}

// --- Authentication Middleware ---

function authMiddleware(req: AuthenticatedRequest, res: Response, next: NextFunction) {
  const token = req.headers.authorization?.replace('Bearer ', '');
  if (!token) {
    return res.status(401).json({ error: 'Missing token' });
  }

  try {
    const decoded = jwt.verify(token, JWT_SECRET) as JwtPayload;
    const userId = decoded.sub as string;
    const user = users[userId];

    if (!user || user.isDisabled) {
      auditLog('auth.denied', { reason: 'disabled-or-missing', userId });
      return res.status(403).json({ error: 'Account not allowed' });
    }

    req.user = user;
    next();
  } catch (err) {
    auditLog('auth.invalid_token', { ip: req.ip });
    return res.status(401).json({ error: 'Invalid token' });
  }
}

// --- Authorization (RBAC + Permissions) ---

function hasPermission(user: User, permission: string): boolean {
  const userPerms = new Set<string>();
  for (const role of user.roles) {
    const perms = ROLE_PERMISSIONS[role] || [];
    perms.forEach(p => userPerms.add(p));
  }
  return userPerms.has(permission);
}

function requirePermission(permission: string) {
  return (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
    if (!req.user) {
      return res.status(401).json({ error: 'Not authenticated' });
    }

    if (!hasPermission(req.user, permission)) {
      auditLog('auth.forbidden', {
        userId: req.user.id,
        permission,
        path: req.path
      });
      return res.status(403).json({ error: 'Forbidden' });
    }

    next();
  };
}

// Optional: resource-level ownership check
function requireSelfOrPermission(permission: string, paramName = 'id') {
  return (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
    if (!req.user) {
      return res.status(401).json({ error: 'Not authenticated' });
    }

    const targetId = req.params[paramName];
    if (req.user.id === targetId) {
      return next(); // user can always act on themselves (customize as needed)
    }

    if (!hasPermission(req.user, permission)) {
      auditLog('auth.forbidden_resource', {
        userId: req.user.id,
        targetId,
        permission,
        path: req.path
      });
      return res.status(403).json({ error: 'Forbidden' });
    }

    next();
  };
}

// --- Routes ---

// View own profile (self-access allowed)
app.get('/api/users/:id', authMiddleware, requireSelfOrPermission('user:read'), (req: AuthenticatedRequest, res: Response) => {
  const target = users[req.params.id];
  if (!target) {
    return res.status(404).json({ error: 'User not found' });
  }
  res.json({ user: target });
});

// Disable user account (admin-only, heavily audited and rate-limited)
app.post(
  '/api/admin/users/:id/disable',
  sensitiveLimiter,
  authMiddleware,
  requirePermission('user:disable'),
  (req: AuthenticatedRequest, res: Response) => {
    const targetId = req.params.id;
    const target = users[targetId];

    if (!target) {
      return res.status(404).json({ error: 'User not found' });
    }

    if (target.id === req.user!.id) {
      return res.status(400).json({ error: 'Cannot disable own account' });
    }

    if (target.isDisabled) {
      return res.status(409).json({ error: 'User already disabled' });
    }

    target.isDisabled = true;

    auditLog('user.disabled', {
      actorId: req.user!.id,
      targetId,
      ip: req.ip
    });

    res.json({ status: 'disabled', targetId });
  }
);

// Audit log viewing (auditor/admin)
app.get('/api/audit/logs', authMiddleware, requirePermission('audit:read'), (_req: AuthenticatedRequest, res: Response) => {
  // In reality, stream from log system with pagination and redaction
  res.json({ message: 'Audit logs would be returned here.' });
});

// Global error handler
app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
  console.error('Unexpected error', err);
  const status = isProd ? 500 : 500;
  res.status(status).json({ error: 'Internal server error' });
});

const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`RBAC API listening on port ${port} (env=${process.env.NODE_ENV || 'dev'})`);
});
```

**Defense in Depth Layers**:
1. **Authentication + Account State**: `authMiddleware` verifies the JWT and checks `isDisabled` before anything else.
   ```typescript
   if (!user || user.isDisabled) {
     auditLog('auth.denied', { reason: 'disabled-or-missing', userId });
     return res.status(403).json({ error: 'Account not allowed' });
   }
   ```
2. **Role/Permission-Based Authorization**: Centralized `hasPermission` and `requirePermission` ensure that even authenticated users are constrained by explicit permissions.
   ```typescript
   if (!hasPermission(req.user, permission)) {
     return res.status(403).json({ error: 'Forbidden' });
   }
   ```
3. **Resource-Level Checks + Rate Limiting**: `requireSelfOrPermission` guards per-resource access, while `sensitiveLimiter` throttles sensitive admin operations to limit abuse.
   ```typescript
   app.post('/api/admin/users/:id/disable', sensitiveLimiter, authMiddleware, requirePermission('user:disable'), handler);
   ```

**Additional Protections**:
- **Environment-specific hardening**: Use `NODE_ENV` to enforce secure defaults in production (strong secrets, stricter logging, secure cookies if applicable).
- **Security headers via Helmet**: Mitigates common web risks (XSS, clickjacking) that can be chained with authorization flaws.
- **Structured audit logging**: `auditLog` records who did what, to which resource, and from where, supporting incident response, anomaly detection, and compliance.
